let itensExcel = $input.all();

const mapaContratos = {
  "04": "DETRAN", "07": "ADM CONTATO", "07.03": "INSTITUTO PCD",
  "10": "SEDUC SEDE", "11": "SEDUC ESCOLA", "11.02": "SEDUC INTERIOR",
  "15": " BARCO CONTATO", "74": "CETAM", "78": "APRENDIZES",
  "79": "TRE PB", "84": "ESTAGIÁRIOS", "85": "SEMSA"
};

function limparValor(valor) {
  if (valor === undefined || valor === null || valor === '') return 0;
  if (typeof valor === 'number') return valor;
  let limpo = String(valor).replace(/[R$\s]/g, '').replace(',', '.');
  return parseFloat(limpo) || 0;
}

for (let item of itensExcel) {
  let valorCesta = limparValor(item.json['VALOR - CESTA'] || item.json['Valor - Cesta'] || item.json['VALOR CESTA']);

  let tipoTrabalhador = String(item.json['Intermitente?'] || item.json['intermitente?'] || '').trim();
  item.json.e_intermitente = (tipoTrabalhador.toUpperCase() === 'INTERMITENTE');

  let chapaRaw = item.json['Chapa'] || item.json['Funcionário'] || item.json['CHAPA'] || '';
  item.json.chapa_formatada = String(chapaRaw).replace(/\D/g, '').padStart(6, '0');

  let codigoRaw = item.json['Código'] || "";
  let nomeContrato = "CONTRATO_DESCONHECIDO";
  let partesCodigo = codigoRaw.split('.');
  if (partesCodigo.length >= 4) {
    let base = partesCodigo[2].slice(-2);
    let sub = partesCodigo[3];
    let composto = base + "." + sub;
    if (mapaContratos[composto]) nomeContrato = composto + "-" + mapaContratos[composto];
    else if (mapaContratos[base]) nomeContrato = base + "-" + mapaContratos[base];
    else nomeContrato = "COD-" + base;
  }
  item.json.nome_contrato = nomeContrato;

  let amounts = [];
  if (valorCesta > 0) amounts.push({ "category": "FOOD_AID", "amount": Math.round(valorCesta * 100) });

  item.json.amounts_totais = amounts;
  item.json.motivo_cesta = item.json['Motivo'] || "";
  item.json.status_cesta = item.json['Cesta Básica - Valor'] || "";

  delete item.json['VR - SALDO'];
  delete item.json['VR - Saldo'];
  delete item.json['VT - SALDO'];
  delete item.json['VT - Saldo'];
  delete item.json['Interior?'];
  delete item.json['interior?'];
}
return itensExcel;

let cajuResponses = $('1. Buscar ID').all();
let excelData = $('Definir Benefícios').all(); 

let listaTodosFuncionarios = [];
let nomeContrato = excelData.length > 0 ? excelData[0].json.nome_contrato : "CONTRATO";

for (let i = 0; i < cajuResponses.length; i++) {
  let emp;
  try {
    emp = cajuResponses[i].json.items[0];
  } catch (e) {
    continue;
  }

  if (!emp || !emp.employeeId) continue;

  // Pula funcionários arquivados
  if (emp.isArchived === true) continue;

  let amountsUnificados = excelData[i].json.amounts_totais;

  if (amountsUnificados && amountsUnificados.length > 0) {
    listaTodosFuncionarios.push({
      "employeeId": emp.employeeId,
      "amounts": amountsUnificados
    });
  }
}

if (listaTodosFuncionarios.length === 0) return [];

let hoje = new Date();
let mesCompetencia = String(hoje.getMonth() + 1).padStart(2, '0') + "-" + hoje.getFullYear();
let referencia = $('Webhook').first().json.body.referencia || "CESTA";

// Nome limitado a 27 caracteres (limite da API Caju)
let nomePedido = (referencia + "-" + nomeContrato + "-" + mesCompetencia).substring(0, 27);

let pacoteFinal = {
  "sponsorId": "5ff5cdc3-c55a-46b3-8a47-29479bf5ad35",
  "name": nomePedido,
  "allowances": listaTodosFuncionarios
};

return [{ json: pacoteFinal }];

// 1. Pega o ID que a Caju acabou de gerar
let idPedido = $input.first().json.id || $input.first().json.allowanceOrderId;

// 2. Pega o pacote de benefícios que NÓS montamos na caixinha "Agrupar Tudo"
let pacoteEnviado = $('Agrupar Tudo').first().json;

// 3. Faz a soma exata de todos os centavos APENAS da Cesta de todos os funcionários
let valorTotalCesta = 0;

if (pacoteEnviado && pacoteEnviado.allowances) {
  for (let funcionario of pacoteEnviado.allowances) {
     if (funcionario.amounts) {
        for (let beneficio of funcionario.amounts) {
           // TRAVA DE SEGURANÇA: Soma apenas se a categoria for FOOD_AID (Cesta/Alimentação)
           if (beneficio.category === "FOOD_AID") {
               valorTotalCesta += beneficio.amount;
           }
        }
     }
  }
}

// 4. Entrega a bandeja pronta para o PIX
return [{
  json: {
    "id_pedido": idPedido,
    "valor_pagamento": valorTotalCesta
  }
}];

let items = $input.all();

for (let item of items) {
  // 1. Pega o texto gigante do seu nó
  let base64String = item.json.pixCode.encodedImage;

  // 2. Prepara a gaveta de arquivos do n8n
  item.binary = item.binary || {};

  // 3. Converte o texto em um arquivo de imagem PNG real
  // Mudamos o nome aqui para 'data', para combinar com o Google Drive!
  item.binary.data = {
    data: base64String,
    mimeType: 'image/png',
    fileName: 'QRCode_Pedido.png'
  };
}

return items;

