             <tot:Contexto>CODCOLIGADA=3; USUARIO=003080</tot:Contexto>
          </tot:SaveRecord>
       </soapenv:Body>
    </soapenv:Envelope>`;
  }

  registros.push({ json: { tipo: 'CREDITO_CESTA', chapa, nome, soapBody: montarSoap(3, valorCesta, tpBenFinal, eIntermitente) } });
}
return registros;

