let items = $input.all();

// ========================================================
// 1. --- PREPARAR O NOME DO CONTRATO (ITEM DO MONDAY) ---
// ========================================================
let nomeContratoSujo = $('Definir Benefícios').first().json.nome_contrato || "";
let partesContrato = nomeContratoSujo.split('-');
let nomeContratoLimpo = partesContrato.length > 1 ? partesContrato[1].trim() : nomeContratoSujo.trim();

// 🚨 TRADUTOR DE CONTRATOS (Evita erros no Monday) 🚨
if (nomeContratoLimpo === "ADM CONTATO") {
  nomeContratoLimpo = "ADMINISTRATIVO - CONTATO";
}

// ========================================================
