let mesAlvo = mesWebhook;
let anoAlvo = anoWebhook;

// REGRA DE NEGÓCIO: Só retrocede 1 mês se for a 1ª Quinzena
if (referencia === "1º QUINZENA" || referencia === "1ª QUINZENA") {
  mesAlvo = mesWebhook - 1;

  // Proteção da virada do ano: Se retroceder de Janeiro (1) fica 0, então vai para Dezembro (12)
  if (mesAlvo < 1) {
    mesAlvo = 12;
    anoAlvo -= 1;
  }
} 
// Se for 2ª Quinzena, ele simplesmente ignora o bloco de cima e mantém o mês atual!

// Mapeamento dos meses para texto em caixa alta
const dicionarioMeses = {
  1: "JANEIRO", 2: "FEVEREIRO", 3: "MARÇO", 4: "ABRIL",
  5: "MAIO", 6: "JUNHO", 7: "JULHO", 8: "AGOSTO",
  9: "SETEMBRO", 10: "OUTUBRO", 11: "NOVEMBRO", 12: "DEZEMBRO"
};

let nomeMes = dicionarioMeses[mesAlvo];

// Pega os últimos 2 dígitos do ano já ajustado (ex: 2026 vira "26")
let anoFormatado = anoAlvo.toString().slice(-2);

// ========================================================
// 3. --- ENTREGAR AS VARIÁVEIS PRONTAS ---
// ========================================================
for (let item of items) {
