//   2. Crédito VT → CODBENEFICIO=2, TPBEN=1 (mensal)
//   3. Boleto VR  → CODBENEFICIO=1, TPBEN=0 (diário)  [se houver]
//   4. Boleto VT  → CODBENEFICIO=2, TPBEN=0 (diário)  [se houver]
// ============================================================

// AJUSTE o nome do nó conforme seu workflow
const dados = $('Code in JavaScript8').first().json; // Nó 17

const hoje = new Date();
const anoComp = hoje.getFullYear();
const mesComp = hoje.getMonth() + 1; // getMonth() é 0-indexed
const chapa = dados.chapaRM;
const nome = dados.nomeEmpregado;

// Função auxiliar para montar o SOAP envelope
function montarSoap(codBeneficio, vlrTotal, tpBen) {
  const xml = `<PRJ3230976>
              <ZMDHSTBENFUNC>
                <ID>-1</ID>
                <CODCOLIGADA>3</CODCOLIGADA>
                <ANOCOMP>${anoComp}</ANOCOMP>
                <MESCOMP>${mesComp}</MESCOMP>
                <ANOREF>${anoComp}</ANOREF>
                <MESREF>${mesComp}</MESREF>
                <CHAPA>${chapa}</CHAPA>
                <NOME>${nome}</NOME>
                <CODBENEFICIO>${codBeneficio}</CODBENEFICIO>
                <VLRTOTAL>${vlrTotal}</VLRTOTAL>
                <TPBEN>${tpBen}</TPBEN>
                <CATFUN>1</CATFUN>
              </ZMDHSTBENFUNC>
            </PRJ3230976>`;

  return `<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:tot="http://www.totvs.com/">
   <soapenv:Header/>
   <soapenv:Body>
      <tot:SaveRecord>
         <tot:DataServerName>RMSPRJ3230976Server</tot:DataServerName>
         <tot:XML><![CDATA[${xml}]]></tot:XML>
         <tot:Contexto>CODCOLIGADA=3; USUARIO=003080</tot:Contexto>
      </tot:SaveRecord>
   </soapenv:Body>
</soapenv:Envelope>`;
}

const registros = [];

// --- Crédito VR (sempre, se > 0) ---
if (dados.creditoVR > 0) {
  registros.push({
    tipo: 'CREDITO_VR',
    soapBody: montarSoap(1, dados.creditoVR, 1),
    valor: dados.creditoVR
  });
}

// --- Crédito VT (sempre, se > 0) ---
if (dados.creditoVT > 0) {
  registros.push({
    tipo: 'CREDITO_VT',
    soapBody: montarSoap(2, dados.creditoVT, 1),
    valor: dados.creditoVT
  });
}

// --- Boleto VR (só se houver) ---
if (dados.boletoVR > 0) {
  registros.push({
    tipo: 'BOLETO_VR',
    soapBody: montarSoap(1, dados.boletoVR, 0),
    valor: dados.boletoVR
  });
}

