if (dados.boletoVT > 0) {
  registros.push({
    tipo: 'BOLETO_VT',
    soapBody: montarSoap(2, dados.boletoVT, 0),
    valor: dados.boletoVT
  });
}

// Retorna array de itens — cada um será processado pelo nó seguinte
return registros.map(r => ({ json: r }));

