// Conta apenas horas de segunda a sexta
// ============================================================
function calcularHorasUteis(inicio, fim) {
  if (inicio >= fim) return 0;

  let horasUteis = 0;
  const cursor = new Date(inicio);

  // Avança hora a hora (otimizado: pula dias inteiros de fim de semana)
  while (cursor < fim) {
    const diaSemana = cursor.getDay(); // 0=Dom, 6=Sáb

    if (diaSemana === 0) {
      // Domingo → pula para segunda 00:00
      cursor.setDate(cursor.getDate() + 1);
      cursor.setHours(0, 0, 0, 0);
      continue;
    }
    if (diaSemana === 6) {
      // Sábado → pula para segunda 00:00
      cursor.setDate(cursor.getDate() + 2);
      cursor.setHours(0, 0, 0, 0);
      continue;
    }

    // Dia útil — calcula horas restantes até o fim do dia ou até 'fim'
    const fimDoDia = new Date(cursor);
    fimDoDia.setDate(fimDoDia.getDate() + 1);
    fimDoDia.setHours(0, 0, 0, 0);

    const limiteCalc = fim < fimDoDia ? fim : fimDoDia;
    const diffMs = limiteCalc.getTime() - cursor.getTime();
    horasUteis += diffMs / (1000 * 60 * 60);

    cursor.setTime(fimDoDia.getTime());
  }

  return horasUteis;
}

function calcularDiasUteis(inicio, fim) {
  if (inicio >= fim) return 0;

  let dias = 0;
  const cursor = new Date(inicio);
  cursor.setHours(0, 0, 0, 0);

  const fimDia = new Date(fim);
  fimDia.setHours(0, 0, 0, 0);

  while (cursor <= fimDia) {
    const diaSemana = cursor.getDay();
    if (diaSemana !== 0 && diaSemana !== 6) {
      dias++;
    }
    cursor.setDate(cursor.getDate() + 1);
  }

  // Se inicio e fim são no mesmo dia, conta como parte de 1 dia
  return Math.max(dias - 1, 0);
}

const limiteHorasUteis = HORAS_INATIVIDADE;
const itensParaAnalisar = [];
const pulseIDsVistos = new Set();

for (const item of $input.all()) {
  const pid = String(item.json.pulseID);

  // DEDUP: se já processamos esse pulseID nesta execução, pula
  if (pulseIDsVistos.has(pid)) continue;
  pulseIDsVistos.add(pid);

  // PROTEÇÃO NaN: se lastupdate for inválido, pula o item
  const lastUpdate = new Date(item.json.lastupdate);
  if (isNaN(lastUpdate.getTime())) {
    continue;
  }

  // Calcula horas e dias ÚTEIS (sem contar fins de semana)
  const horasUteisInativo = calcularHorasUteis(lastUpdate, agora);
  const diasUteisInativo = calcularDiasUteis(lastUpdate, agora);

  // Descarta itens que ainda não passaram 24h úteis sem atualização
  if (horasUteisInativo < limiteHorasUteis) continue;

  // PROTEÇÃO DUPLA contra renotificação:
  const foiNotificado = item.json.notificado === true || item.json.notificado === 'true';

  if (foiNotificado && item.json.ultima_notificacao) {
    const ultimaNotificacao = new Date(item.json.ultima_notificacao);

    if (!isNaN(ultimaNotificacao.getTime())) {
      // Calcula horas úteis desde última notificação
      const horasUteisDesdeNotificacao = calcularHorasUteis(ultimaNotificacao, agora);

      // Check 1: Se a última cobrança foi há menos de 24h úteis, pula
      if (horasUteisDesdeNotificacao < limiteHorasUteis) {
        continue;
      }

      // Check 2: Se já foi cobrado HOJE (mesmo dia), pula
      const mesmoAno = ultimaNotificacao.getFullYear() === agora.getFullYear();
      const mesmoMes = ultimaNotificacao.getMonth()    === agora.getMonth();
      const mesmoDia = ultimaNotificacao.getDate()     === agora.getDate();

      if (mesmoAno && mesmoMes && mesmoDia) {
        continue;
      }
    }
  }

  itensParaAnalisar.push({
    json: {
      pulseID:            item.json.pulseID,
      boardID:            item.json.boardID,
      lastupdate:         item.json.lastupdate,
      notificado:         item.json.notificado,
      ultima_notificacao: item.json.ultima_notificacao,
      horas_inativo:      Math.round(horasUteisInativo),
      dias_inativo:       diasUteisInativo,
      id_datatable:       item.json.id
    }
  });
}

return itensParaAnalisar;

