const userIds = [];
if (dados.user_id_quem_deve) {
  userIds.push(Number(dados.user_id_quem_deve));
}
if (dados.user_ids_adicionais && Array.isArray(dados.user_ids_adicionais)) {
  dados.user_ids_adicionais.forEach(id => {
    const numId = Number(id);
    if (numId && !userIds.includes(numId)) {
      userIds.push(numId);
    }
  });
}

// IDs do PSC (ciência)
const userIdsPSC = [];
if (dados.user_ids_psc && Array.isArray(dados.user_ids_psc)) {
  dados.user_ids_psc.forEach(id => {
    const numId = Number(id);
    if (numId && !userIds.includes(numId) && !userIdsPSC.includes(numId)) {
      userIdsPSC.push(numId);
    }
  });
}

const escapeGraphQL = (str) => {
  return str
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '');
};

const bodyEscapado = escapeGraphQL(dados.mensagem_monday_html);
const ultimoUpdateId = dados.ultimoUpdateId || null;

// Mutation do create_update (reply)
let mutationUpdate;
if (ultimoUpdateId) {
  mutationUpdate = {
    query: `mutation { create_update(item_id: ${dados.pulseID}, parent_id: ${ultimoUpdateId}, body: "${bodyEscapado}") { id } }`
  };
} else {
  mutationUpdate = {
    query: `mutation { create_update(item_id: ${dados.pulseID}, body: "${bodyEscapado}") { id } }`
  };
}

