function norm(s){return String(s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^\x00-\x7F]/g,'');}
function trunc(s,m){const n=String(s);return n.length<=m?n:n.substring(0,m-3).trimEnd()+'...';}
function rankColor(v){v=Number(v);if(v>=5)return[0.55,0.10,0.10];if(v>=3)return[0.80,0.20,0.20];if(v===2)return[0.83,0.44,0.13];return[0.80,0.63,0.13];}

function criarGerador(){
  let pdf='%PDF-1.4\n';const objetos=[],offsets={};
  const F={n:'F1',b:'F2'};
  const C={
    bg:[0.925,0.945,0.949],cardBg:[0.97,0.97,0.98],cardBdr:[0.78,0.80,0.84],
    headerBg:[0.051,0.231,0.431],headerTx:[1,1,1],headerSub:[0.784,0.588,0.243],
    kpiBg:[0.97,0.97,0.98],kpiNum:[0.051,0.231,0.431],kpiLabel:[0.35,0.38,0.42],
    highlight:[0.784,0.588,0.243],green:[0.18,0.54,0.24],red:[0.70,0.20,0.20],
    textPri:[0.12,0.12,0.14],textSec:[0.35,0.38,0.42],textMut:[0.50,0.52,0.56],
    link:[0.051,0.231,0.431],barTrack:[0.85,0.87,0.90],
    msgBg:[0.902,0.914,0.918],msgBdr:[0.051,0.231,0.431],msgLabel:[0.051,0.231,0.431],
    bAltaBg:[0.95,0.85,0.85],bAltaTx:[0.55,0.15,0.15],
    bMediaBg:[0.97,0.92,0.80],bMediaTx:[0.50,0.38,0.05],
    bBaixaBg:[0.85,0.93,0.85],bBaixaTx:[0.15,0.40,0.15],
    bResBg:[0.82,0.90,0.96],bResTx:[0.10,0.31,0.50],
    setorBg:[0.97,0.97,0.98],setorBdr:[0.80,0.82,0.86],
    prevBar:[0.78,0.80,0.84],greenBar:[0.23,0.67,0.33],redBar:[0.80,0.22,0.22],grayBar:[0.54,0.56,0.60],
  };
  const rgb=c=>c[0].toFixed(3)+' '+c[1].toFixed(3)+' '+c[2].toFixed(3);
  const esc=s=>String(s).replace(/[()\\]/g,'\\$&');
  const pa=[];
  function rrPath(x,y,w,h,r){const k=0.5523*r;return(x+r)+' '+y+' m '+(x+w-r)+' '+y+' l '+(x+w-r+k)+' '+y+' '+(x+w)+' '+(y+r-k)+' '+(x+w)+' '+(y+r)+' c '+(x+w)+' '+(y+h-r)+' l '+(x+w)+' '+(y+h-r+k)+' '+(x+w-r+k)+' '+(y+h)+' '+(x+w-r)+' '+(y+h)+' c '+(x+r)+' '+(y+h)+' l '+(x+r-k)+' '+(y+h)+' '+x+' '+(y+h-r+k)+' '+x+' '+(y+h-r)+' c '+x+' '+(y+r)+' l '+x+' '+(y+r-k)+' '+(x+r-k)+' '+y+' '+(x+r)+' '+y+' c h';}
  function pagina(){
    const ops=[];const idx=pa.length;pa.push([]);
    return{
      rr(x,y,w,h,r,cf,cb,sw){ops.push('q');const p=rrPath(x,y,w,h,r||8);if(cf&&cb)ops.push(rgb(cf)+' rg '+rgb(cb)+' RG '+(sw||0.5)+' w '+p+' B');else if(cf)ops.push(rgb(cf)+' rg '+p+' f');else if(cb)ops.push(rgb(cb)+' RG '+(sw||0.5)+' w '+p+' S');ops.push('Q');},
      rect(x,y,w,h,cf){ops.push('q '+rgb(cf)+' rg '+x+' '+y+' '+w+' '+h+' re f Q');},
      pill(x,y,w,h,cf){if(w<1)return;const r=Math.min(h/2,w/2);ops.push('q '+rgb(cf)+' rg '+rrPath(x,y,w,h,r)+' f Q');},
      txt(x,y,t,fonte,tam,cor){ops.push('q BT /'+(fonte||F.n)+' '+(tam||10)+' Tf '+rgb(cor||C.textPri)+' rg '+x+' '+y+' Td ('+esc(t)+') Tj ET Q');},
      txtC(cx,y,t,fonte,tam,cor){const w=String(t).length*(tam||10)*0.48;ops.push('q BT /'+(fonte||F.n)+' '+(tam||10)+' Tf '+rgb(cor||C.textPri)+' rg '+(cx-w/2)+' '+y+' Td ('+esc(t)+') Tj ET Q');},
      link(x,y,w,h,url){pa[idx].push('<</Type /Annot /Subtype /Link /Rect ['+x+' '+y+' '+(x+w)+' '+(y+h)+'] /Border [0 0 0] /A <</S /URI /URI ('+url+')>>>>')},
      build(){return ops.join('\n');}
    };
  }
  function addObj(id,c){objetos.push({id,conteudo:c});}
  function compilar(streams){
    const nf=3+streams.length*2;
    addObj(1,'<</Type /Catalog /Pages 2 0 R>>');
    addObj(2,'<</Type /Pages /Kids ['+streams.map((_,i)=>(3+i*2)+' 0 R').join(' ')+'] /Count '+streams.length+'>>');
    streams.forEach((s,i)=>{const pid=3+i*2,sid=4+i*2,len=Buffer.byteLength(s,'latin1');let ann='';if(pa[i]&&pa[i].length>0)ann=' /Annots [ '+pa[i].join(' ')+' ]';addObj(pid,'<</Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Contents '+sid+' 0 R /Resources <</Font <</F1 '+nf+' 0 R /F2 '+(nf+1)+' 0 R>>>>'+ann+'>>');addObj(sid,'<</Length '+len+'>>\nstream\n'+s+'\nendstream');});
    addObj(nf,'<</Type /Font /Subtype /Type1 /BaseFont /Helvetica /Encoding /WinAnsiEncoding>>');
    addObj(nf+1,'<</Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold /Encoding /WinAnsiEncoding>>');
    objetos.forEach(({id,conteudo})=>{offsets[id]=Buffer.byteLength(pdf,'latin1');pdf+=id+' 0 obj\n'+conteudo+'\nendobj\n';});
    const xp=Buffer.byteLength(pdf,'latin1'),mx=Math.max(...objetos.map(o=>o.id));
    let xref='xref\n0 '+(mx+1)+'\n0000000000 65535 f \n';
    for(let i=1;i<=mx;i++)xref+=(offsets[i]!==undefined?String(offsets[i]).padStart(10,'0'):'0000000000')+' 00000 n \n';
    xref+='trailer\n<</Size '+(mx+1)+' /Root 1 0 R>>\nstartxref\n'+xp+'\n%%EOF';
    return Buffer.from(pdf+xref,'latin1');
  }
  return{pagina,compilar,C,F};
}

function wrapText(t,mw){const w=String(t).split(' ');const l=[];let ln='';for(const x of w){const tt=(ln+' '+x).trim();if(tt.length*4.2>mw){if(ln)l.push(ln);ln=x;}else ln=tt;}if(ln)l.push(ln);return l;}

function calcVar(atual,anterior,invertido){
  if(!anterior||anterior===0)return{txt:'',cor:null};
  const pct=Math.round(((atual-anterior)/anterior)*100);
  if(pct>0)return{txt:'+'+pct+'%',cor:invertido?'green':'red'};
  if(pct<0)return{txt:pct+'%',cor:invertido?'red':'green'};
  return{txt:'=',cor:null};
}
function calcVarD(atual,anterior){
  const diff=Math.round((atual-anterior)*10)/10;
  if(diff>0)return{txt:'+'+diff+'d',cor:'red'};
  if(diff<0)return{txt:diff+'d',cor:'green'};
  return{txt:'=',cor:null};
}

