  y-=16;
  if(y-80<35)y=newPage();
  p.txt(MX,y,'DEMANDAS COBRADAS NA SEMANA',F.b,10,C.textMut);
  y-=14;

  demandas.forEach(d=>{
    const b=badge[d.urgencia]||badge['baixa'];
    const resumo=d.resumo_demanda||d.motivo||'';
    const msgLines=resumo?wrapText(resumo,510):[];
    const cardH=58+(msgLines.length>0?20+msgLines.length*13+12:0);
    if(y-cardH<35){y=newPage();p.txt(MX,y,'DEMANDAS COBRADAS (cont.)',F.b,10,C.textMut);y-=14;}

    p.rr(MX,y-cardH,LG,cardH,10,C.cardBg,C.cardBdr);
    p.txt(36,y-18,trunc(d.itemName||'',42),F.b,12,C.textPri);
    const diasNum=Number(d.dias_inativo)||0;
    p.txt(520,y-18,diasNum+(diasNum===1?' dia':' dias'),F.b,12,C.textPri);

    const devStr=trunc(d.devedor||'N/A',25);
    const setorD=d._setorDisplay||'N/I';
    p.txt(36,y-35,devStr+'  |  '+setorD,F.n,10,C.textSec);

    const urgText=norm(d.urgencia||'baixa');
    const infoW=(devStr+'  |  '+setorD).length*5;
    let bx=36+infoW+10;
    p.rr(bx,y-39,urgText.length*6+14,16,8,b.bg);
    p.txt(bx+7,y-35,urgText,F.b,8,b.tx);
    if(d.resolvida){bx+=urgText.length*6+20;p.rr(bx,y-39,64,16,8,badge.finalizada.bg);p.txt(bx+7,y-35,'finalizada',F.b,8,badge.finalizada.tx);}

    const url=d.linkDemanda||'https://contato-serv.monday.com/boards/'+d.boardID+'/pulses/'+d.pulseID;
    p.txt(480,y-35,'Acessar demanda →',F.b,8,C.link);
    p.link(478,y-40,110,16,url);

    if(msgLines.length>0){
      const mh=18+msgLines.length*13+6;const my=y-52;
      p.rr(36,my-mh,LG-24,mh,6,C.msgBg);
      p.pill(36,my-mh+3,3,mh-6,C.msgBdr);
      p.txt(46,my-12,'RESUMO DA DEMANDA',F.b,7,C.msgLabel);
      msgLines.forEach((ln,li)=>{p.txt(46,my-24-li*13,ln,F.n,9,C.textSec);});
    }
    y-=cardH+10;
  });

  drawFooter(p,numPag);streams.push(p.build());

  const pdfBuffer=compilar(streams);
  const nomeRem=norm(remetente).replace(/\s+/g,'_');
  const nomeArq='Relatorio_Semanal_'+nomeRem+'_S'+semanaAtual+'.pdf';

  output.push({
    json:{
      temRelatorio:true,tipo:'PDF',nome_arquivo:nomeArq,remetente,
      totalDemandas:totalDem,totalDevedores:totalDev,
      resolvidas,taxaResolucao:taxaRes,mediaDias,
      semana:semanaKey,
      // remoteJid definido pelo node 'Roteador do Relatório'
      historico_semana:semanaKey,
      historico_remetente:remetente,
      historico_total_cobrancas:totalDem,
      historico_total_devedores:totalDev,
      historico_total_resolvidas:resolvidas,
      historico_media_dias:String(mediaDias),
      historico_seg:diasAtual[0],historico_ter:diasAtual[1],
      historico_qua:diasAtual[2],historico_qui:diasAtual[3],historico_sex:diasAtual[4],
    },
    binary:{data:{data:pdfBuffer.toString('base64'),mimeType:'application/pdf',fileName:nomeArq,fileExtension:'pdf'}}
  });
}

if(output.length===0)return[{json:{temRelatorio:false}}];
return output;

