function normalizar(s){return String(s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().trim();}
function capitalizar(s){return String(s).split(' ').map(w=>w.charAt(0).toUpperCase()+w.slice(1).toLowerCase()).join(' ');}
function resolverSetor(d){
  let s=normalizar(d.setorDemandado||'');if(s&&mapaLideres[s])return s;
  const nd=normalizar(d.devedor||'');
  for(const[nf,sf]of Object.entries(funcionarioSetor)){if(nd.includes(normalizar(nf))||normalizar(nf).includes(nd))return normalizar(sf);}
  return '';
}
function resolverSetorDisplay(d){
  const s=resolverSetor(d);if(!s)return'N/I';
  return{'dp':'DP','rh':'RH','ti':'TI','aions':'AIONS'}[s]||capitalizar(s);
}
function determinarRemetente(d){
  const dias=Number(d.dias_inativo)||1,dev=normalizar(d.devedor||''),setor=resolverSetor(d);
  if(dev.includes('joao')&&dev.includes('dr'))return{nome:'Tuca',nivel:'3'};
  const ehL=nomesLideresLista.some(nl=>dev.includes(nl));
  if(ehL){if(dias>=2)return{nome:'Tuca',nivel:'3'};return{nome:'Dr. João',nivel:'2'};}
  if(setor==='comercial'){if(dias>=2)return{nome:'Tuca',nivel:'3'};return{nome:'Dr. João',nivel:'1'};}
  if(dias>=3)return{nome:'Tuca',nivel:'3'};
  if(dias===2)return{nome:'Dr. João',nivel:'2'};
  const lider=setor?(mapaLideres[setor]||'Líder N/I'):'Líder N/I';
  return{nome:lider,nivel:'1'};
}

// ══ LEITURA DE DADOS ══
const rawItems=$('Get row(s)').all();
const vistos=new Set(),cobrancas=[];
for(const item of rawItems){const k=String(item.json.pulseID||item.json.id);if(!vistos.has(k)){vistos.add(k);cobrancas.push(item.json);}}
if(cobrancas.length===0)return[{json:{temRelatorio:false}}];

let cp=[];try{cp=$('Get row(s) - Contagem Relatorio').all();}catch(e){}
const cMap={};for(const r of cp){const n=(r.json.name||r.json.Name||'').trim().toLowerCase();if(n)cMap[n]=Number(r.json.quantidade)||0;}

let cdd=[];try{cdd=$('Get row(s) - Contagem Demanda Relatorio').all();}catch(e){}
const cdMap={};for(const r of cdd){const pp=String(r.json.pulse||'').trim();if(pp)cdMap[pp]=Number(r.json.quantidade)||0;}

let monit=[];try{monit=$('Get row(s) - Monitoramento').all();}catch(e){}
const pendentesSet=new Set();
for(const m of monit)pendentesSet.add(String(m.json.pulseID));

let hist=[];try{hist=$('Get row(s)1').all();}catch(e){}
const agora=new Date();
const dow=agora.getDay()||7;
const seg=new Date(agora);seg.setDate(agora.getDate()-dow+1);
const sex=new Date(seg);sex.setDate(seg.getDate()+4);
const semanaAtual=Math.ceil((agora-new Date(agora.getFullYear(),0,1))/(7*24*60*60*1000));
const semanaKey=agora.getFullYear()+'-S'+semanaAtual;
const semanaAnteriorKey=agora.getFullYear()+'-S'+(semanaAtual-1);
const fmtD=d=>d.toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit'});
const periodo=fmtD(seg)+' a '+fmtD(sex)+'/'+agora.getFullYear();

const historicoMap={};
for(const h of hist){if(String(h.json.semana)===semanaAnteriorKey)historicoMap[String(h.json.remetente).trim()]=h.json;}

// Enriquecer
cobrancas.forEach(d=>{
  d.total_cobracas_devedor=cMap[(d.devedor||'').trim().toLowerCase()]||0;
  d.vezes_cobrado_demanda=cdMap[String(d.pulseID)]||1;
  d.resolvida=!pendentesSet.has(String(d.pulseID));
  d._setorDisplay=resolverSetorDisplay(d);
  // Usa remetente_nome salvo no banco (nível original da cobrança)
  // Fallback para determinarRemetente se não tiver
  if(d.remetente_nome && d.nivel_escalonamento){
    d._remetente={nome:d.remetente_nome,nivel:String(d.nivel_escalonamento)};
  }else{
    d._remetente=determinarRemetente(d);
  }
  // Dia da semana pelo data_cobranca (salvo explicitamente no diário)
  // Fallbacks em cascata para garantir que algum valor seja capturado:
  // 1. data_cobranca (formato ISO)
  // 2. createdAt do n8n (timestamp do registro na DataTable)
  // 3. data atual (assume hoje — comum na primeira semana após implantação)
  let ca = null;
  if (d.data_cobranca) {
    const t = new Date(d.data_cobranca);
    if (!isNaN(t.getTime())) ca = t;
  }
  if (!ca && d.createdAt) {
    const t = new Date(d.createdAt);
    if (!isNaN(t.getTime())) ca = t;
  }
  if (!ca) ca = new Date(); // fallback: hoje
  d._diaSemana = ca.getDay(); // 0=dom,1=seg..5=sex,6=sab
});

const grupos={};
