const output=[];
const nivelSubtitulo={'1':'Cobranças de nível 1 — demandas do seu setor na semana','2':'Cobranças de nível 2 — demandas escaladas na semana','3':'Cobranças de nível 3 — demandas graves na semana'};

for(const[remetente,grupo]of Object.entries(grupos)){
