  const streams=[];const MX=24,LG=564;
  const demandas=grupo.demandas;
  demandas.sort((a,b)=>(Number(b.dias_inativo)||0)-(Number(a.dias_inativo)||0));

  const totalDem=demandas.length;
  const totalDev=[...new Set(demandas.map(d=>d.devedor||'N/A'))].length;
  const resolvidas=demandas.filter(d=>d.resolvida).length;
  const taxaRes=totalDem>0?Math.round(resolvidas/totalDem*100):0;
  const mediaDias=totalDem>0?Math.round(demandas.reduce((a,d)=>a+(Number(d.dias_inativo)||0),0)/totalDem*10)/10:0;
  const nivel=demandas[0]?demandas[0]._remetente.nivel:'1';

  // Histórico anterior
  const prevData=historicoMap[remetente]||null;
  const prevCob=prevData?Number(prevData.total_cobrancas):0;
  const prevRes=prevData?Number(prevData.total_resolvidas):0;
  const prevMed=prevData?Number(prevData.media_dias):0;
  const varCob=calcVar(totalDem,prevCob,false);
  const varRes=calcVar(resolvidas,prevRes,true);
  const varMed=calcVarD(mediaDias,prevMed);

  // Contagem por dia da semana (1=seg..5=sex)
  const diasAtual=[0,0,0,0,0];
  demandas.forEach(d=>{const ds=d._diaSemana;if(ds>=1&&ds<=5)diasAtual[ds-1]++;});
  const diasAnterior=[0,0,0,0,0];
  if(prevData){
    diasAnterior[0]=Number(prevData.seg)||0;diasAnterior[1]=Number(prevData.ter)||0;
    diasAnterior[2]=Number(prevData.qua)||0;diasAnterior[3]=Number(prevData.qui)||0;
    diasAnterior[4]=Number(prevData.sex)||0;
  }
  const maxDia=Math.max(...diasAtual,...diasAnterior,1);

  // Setores
  const setores={};
  demandas.forEach(d=>{const s=d._setorDisplay||'N/I';if(!setores[s])setores[s]={total:0,devs:new Set()};setores[s].total++;setores[s].devs.add(d.devedor||'N/A');});
  const setorList=Object.entries(setores).map(([s,v])=>({nome:s,total:v.total,devs:v.devs.size})).sort((a,b)=>b.total-a.total);

  const badge={
    'alta':{bg:C.bAltaBg,tx:C.bAltaTx},'media':{bg:C.bMediaBg,tx:C.bMediaTx},
    'baixa':{bg:C.bBaixaBg,tx:C.bBaixaTx},'finalizada':{bg:C.bResBg,tx:C.bResTx},
  };

  let numPag=1,p=pagina();
  function drawFooter(pg,n){pg.txt(24,18,'Aions Corp — Sistema de cobrança inteligente',F.n,8,C.textMut);pg.txt(540,18,'Pág. '+n,F.n,8,C.textMut);}
  function newPage(){drawFooter(p,numPag);streams.push(p.build());numPag++;p=pagina();p.rect(0,0,612,792,C.bg);return 760;}

  p.rect(0,0,612,792,C.bg);
  let y=792-20;

  // ── HEADER ──
  p.rr(20,y-90,572,90,12,C.headerBg);
  p.txtC(306,y-32,remetente+' — Relatório semanal',F.b,22,C.headerTx);
  p.txtC(306,y-50,nivelSubtitulo[nivel]||'Cobranças da semana',F.n,10,C.headerSub);
  p.txtC(306,y-66,'Semana '+periodo,F.n,10,[0.69,0.73,0.80]);
  y-=110;

  // ── KPIs COM VARIAÇÃO ──
  const kw=(LG-30)/4;const kpiH=68;
  const kpis=[
    [String(totalDem),'Cobranças',varCob.txt,varCob.cor==='red'?C.red:varCob.cor==='green'?C.green:null,C.kpiNum,false],
    [String(totalDev),'Devedores','',null,C.kpiNum,false],
    [String(resolvidas),'Finalizadas',varRes.txt,varRes.cor==='red'?C.red:varRes.cor==='green'?C.green:null,C.kpiNum,false],
    [taxaRes+'%','Finalização','',null,C.green,false],
  ];
  kpis.forEach(([v,l,vtxt,vcor,ncor,gold],i)=>{
    const kx=MX+i*(kw+10);
    if(gold)p.rr(kx,y-kpiH,kw,kpiH,10,C.kpiBg,C.highlight,1.5);
    else p.rr(kx,y-kpiH,kw,kpiH,10,C.kpiBg,C.cardBdr);
    p.txtC(kx+kw/2,y-24,v,F.b,20,ncor);
    p.txtC(kx+kw/2,y-40,l,F.n,8,C.kpiLabel);
    if(vtxt&&vcor)p.txtC(kx+kw/2,y-54,vtxt,F.b,8,vcor);
  });
  y-=kpiH+16;

  // ── GRÁFICO EVOLUÇÃO DIÁRIA ──
  p.txt(MX,y,'EVOLUÇÃO DIÁRIA',F.b,10,C.textMut);
  // Legenda
  p.rr(LG-196,y-2,10,8,3,C.prevBar);p.txt(LG-182,y-1,'Anterior',F.n,8,C.textMut);
  p.rr(LG-126,y-2,10,8,3,C.greenBar);p.txt(LG-112,y-1,'Abaixo',F.n,8,C.textMut);
  p.rr(LG-66,y-2,10,8,3,C.grayBar);p.txt(LG-52,y-1,'Igual',F.n,8,C.textMut);
  p.rr(LG-12,y-2,10,8,3,C.redBar);p.txt(LG+2,y-1,'Acima',F.n,8,C.textMut);
  y-=18;

  const chH=100,chBot=y-chH,chL=30,chR=582;
  const grW=(chR-chL)/5,barW=grW*0.35,gap=3;
  const diasNome=['Seg','Ter','Qua','Qui','Sex'];

  for(let i=0;i<5;i++){
    const gx=chL+i*grW,cx=gx+grW/2;
    // Anterior
    const ph=(diasAnterior[i]/maxDia)*chH;
    const px=cx-barW-gap/2;
    p.rr(px,chBot,barW,Math.max(ph,3),5,C.prevBar);
    if(prevData)p.txtC(px+barW/2,chBot+ph+3,String(diasAnterior[i]),F.n,7,[0.60,0.62,0.65]);
    // Atual
    const ch2=(diasAtual[i]/maxDia)*chH;
    const cx2=cx+gap/2;
    let bc;
    if(diasAtual[i]>diasAnterior[i])bc=C.redBar;
    else if(diasAtual[i]<diasAnterior[i])bc=C.greenBar;
    else bc=C.grayBar;
    p.rr(cx2,chBot,barW,Math.max(ch2,3),5,bc);
    p.txtC(cx2+barW/2,chBot+ch2+3,String(diasAtual[i]),F.b,9,bc);
    p.txtC(cx,chBot-12,diasNome[i],F.b,9,C.textSec);
  }
  y-=chH+28;

  // ── SETORES ──
  if(setorList.length>0){
    p.txt(MX,y,'COBRANÇAS POR SETOR',F.b,10,C.textMut);
    y-=14;
    const maxST=setorList[0].total;
    const colW=(LG-10)/2;
    for(let i=0;i<setorList.length;i+=2){
      if(y-54<35)y=newPage();
      for(let j=0;j<2&&i+j<setorList.length;j++){
        const s=setorList[i+j];const cx=MX+j*(colW+10);
        p.rr(cx,y-44,colW,44,8,C.setorBg,C.setorBdr);
        p.txt(cx+10,y-14,s.nome,F.b,11,C.kpiNum);
        const ct=s.total===1?'cobrança':'cobranças';
        const dt2=s.devs===1?'devedor':'devedores';
        p.txt(cx+10,y-28,s.total+' '+ct+' | '+s.devs+' '+dt2,F.n,8,C.textSec);
        const bw=colW-20;
        p.pill(cx+10,y-40,bw,5,C.barTrack);
        p.pill(cx+10,y-40,Math.max(bw*(s.total/maxST),4),5,rankColor(s.total));
      }
      y-=54;
    }
  }

  // ── RANKINGS LADO A LADO ──
  y-=6;
  const rq={};demandas.forEach(d=>{const dev=d.devedor||'N/A';rq[dev]=(rq[dev]||0)+1;});
  const tq=Object.entries(rq).sort((a,b)=>b[1]-a[1]).slice(0,5);
  const mxq=tq[0]?tq[0][1]:1;
  const rd={};demandas.forEach(d=>{const dev=d.devedor||'N/A';const dias=Number(d.dias_inativo)||0;if(!rd[dev]||dias>rd[dev])rd[dev]=dias;});
  const td=Object.entries(rd).sort((a,b)=>b[1]-a[1]).slice(0,5);
  const mxd=td[0]?td[0][1]:1;
  const maxRows=Math.max(tq.length,td.length);
  const rkH=18+maxRows*18+6;
  if(y-rkH<35)y=newPage();

  const colW2=(LG-16)/2;const lx=MX,rx=MX+colW2+16;
  p.txt(lx,y,'POR QUANTIDADE',F.b,9,C.textMut);p.txt(rx,y,'POR DIAS PARADO',F.b,9,C.textMut);
  y-=14;
  for(let i=0;i<maxRows;i++){
    if(i<tq.length){
      const[nm,vl]=tq[i];
      p.txt(lx,y,trunc(nm,20),F.n,9,C.textPri);
      const bx=lx+110,bw2=colW2-140;
      p.pill(bx,y-2,bw2,7,C.barTrack);p.pill(bx,y-2,Math.max(bw2*(vl/mxq),4),7,rankColor(vl));
      p.txt(lx+colW2-5,y,String(vl),F.b,9,C.textPri);
    }
    if(i<td.length){
      const[nm,vl]=td[i];
      p.txt(rx,y,trunc(nm,20),F.n,9,C.textPri);
      const bx=rx+110,bw2=colW2-140;
      p.pill(bx,y-2,bw2,7,C.barTrack);p.pill(bx,y-2,Math.max(bw2*(vl/mxd),4),7,rankColor(vl));
      p.txt(rx+colW2-5,y,vl+'d',F.b,9,C.textPri);
    }
    y-=18;
  }

  // ── DEMANDAS COBRADAS (por último) ──
  y-=16;
  if(y-80<35)y=newPage();
  p.txt(MX,y,'DEMANDAS COBRADAS NA SEMANA',F.b,10,C.textMut);
  y-=14;

  demandas.forEach(d=>{
    const b=badge[d.urgencia]||badge['baixa'];
    const resumo=d.resumo_demanda||d.motivo||'';
    const msgLines=resumo?wrapText(resumo,510):[];
    const cardH=58+(msgLines.length>0?20+msgLines.length*13+12:0);
