    if(d.resolvida){bx+=urgText.length*6+20;p.rr(bx,y-39,64,16,8,badge.finalizada.bg);p.txt(bx+7,y-35,'finalizada',F.b,8,badge.finalizada.tx);}

    const url=d.linkDemanda||'https://contato-serv.monday.com/boards/'+d.boardID+'/pulses/'+d.pulseID;
    p.txt(480,y-35,'Acessar demanda →',F.b,8,C.link);
    p.link(478,y-40,110,16,url);

    if(msgLines.length>0){
      const mh=18+msgLines.length*13+6;const my=y-52;
      p.rr(36,my-mh,LG-24,mh,6,C.msgBg);
      p.pill(36,my-mh+3,3,mh-6,C.msgBdr);
      p.txt(46,my-12,'RESUMO DA DEMANDA',F.b,7,C.msgLabel);
      msgLines.forEach((ln,li)=>{p.txt(46,my-24-li*13,ln,F.n,9,C.textSec);});
    }
    y-=cardH+10;
  });

  drawFooter(p,numPag);streams.push(p.build());

  const pdfBuffer=compilar(streams);
  const nomeRem=norm(remetente).replace(/\s+/g,'_');
  const nomeArq='Relatorio_Semanal_'+nomeRem+'_S'+semanaAtual+'.pdf';

  output.push({
    json:{
      temRelatorio:true,tipo:'PDF',nome_arquivo:nomeArq,remetente,
      totalDemandas:totalDem,totalDevedores:totalDev,
      resolvidas,taxaResolucao:taxaRes,mediaDias,
