function normalizar(s){return String(s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().trim();}
function capitalizar(s){return String(s).split(' ').map(w=>w.charAt(0).toUpperCase()+w.slice(1).toLowerCase()).join(' ');}
function resolverSetor(d){
  let s=normalizar(d.setorDemandado||'');
  if(s&&mapaLideres[s])return s;
  const nd=normalizar(d.devedor||'');
  for(const[ln,st]of Object.entries(liderParaSetor)){if(nd===ln||nd.includes(ln)||ln.includes(nd))return st;}
  for(const[nf,sf]of Object.entries(funcionarioSetor)){if(nd.includes(normalizar(nf))||normalizar(nf).includes(nd))return normalizar(sf);}
  return '';
}
function resolverSetorDisplay(d){
  const s=resolverSetor(d);if(!s)return'N/I';
  return{'dp':'DP','rh':'RH','ti':'TI','aions':'AIONS'}[s]||capitalizar(s);
}
function determinarRemetente(d){
  const dias=Number(d.dias_inativo)||1,dev=normalizar(d.devedor||''),setor=resolverSetor(d);
  if(dev.includes('joao')&&dev.includes('dr'))return{nome:'Tuca',nivel:'3'};
  const ehL=nomesLideresLista.some(nl=>dev.includes(nl));
  if(ehL){if(dias>=2)return{nome:'Tuca',nivel:'3'};return{nome:'Dr. João',nivel:'2'};}
  if(setor==='comercial'){if(dias>=2)return{nome:'Tuca',nivel:'3'};return{nome:'Dr. João',nivel:'1'};}
  if(dias>=3)return{nome:'Tuca',nivel:'3'};
  if(dias===2)return{nome:'Dr. João',nivel:'2'};
  const lider=setor?(mapaLideres[setor]||'Lider N/I'):'Lider N/I';
  return{nome:lider,nivel:'1'};
}

