        const cx=MX+LABEL_W+INNER_PAD+i*col_w+col_w/2,bw=col_w*0.72,bx=cx-bw/2;
        if(val===null){
          p.rr(bx,baseline,bw,16,3,[0.80,0.82,0.84]);
          p.txtC(cx,baseline+16+NAME_GAP,DIAS[i],F.b,9,[0.72,0.74,0.78]);
          p.txtC(cx,baseline-NUM_Y_OFF+4,'—',F.n,9,[0.72,0.74,0.78]);
        }else{
          let bc,nc;
          if(g_max>0&&val===g_max&&g_max!==g_min){bc=C.evoDark;nc=C.evoDark;}
          else if(g_max>0&&val===g_min&&g_min!==g_max){bc=C.evoGold;nc=C.evoGold;}
          else if(s_max>0&&val===s_max){bc=C.evoRed;nc=C.evoRed;}
          else if(s_max>0&&val===s_min&&s_min!==s_max){bc=C.evoGreen;nc=C.evoGreen;}
          else{bc=C.evoNormal;nc=C.textSec;}
          const bh=val>0?Math.max(Math.floor((val/g_max)*MAX_BAR),5):0;
          if(bh>0){
            p.txtC(cx,baseline+bh+NAME_GAP+2,String(val),F.b,11,nc);
            p.rr(bx,baseline,bw,bh,4,bc);
          } else {
            // valor zero: stub mínimo + número no topo
            p.rr(bx,baseline,bw,4,2,C.evoNormal);
            p.txtC(cx,baseline+4+NAME_GAP,String(val),F.n,9,C.textSec);
          }
          p.txtC(cx,baseline-NUM_Y_OFF,DIAS[i],F.b,9,C.textSec);
        }
      });
      y-=ROW_H+8;
    });
    y-=4;
  }

  // DEMANDAS — draw_demanda(): card_h=56+msg_h, rr fill=(1,1,1)
  // txt(PAD+10,y-16,11bold), txtR(PW-PAD-8,y-16,11bold)
  // txt(PAD+10,y-29,9), PILL_H=13,PILL_Y=y-43,TXT_Y=PILL_Y+PILL_H/2-3
  // txtR(PW-PAD-8,y-36,'Acessar demanda >',7bold)
  // my=y-52, mh=10+len*12+6
  {
    if(y-80<40)y=newPage();
    const secLbl=ehTuca?'DEMANDAS CRITICAS DO MES':'DEMANDAS COBRADAS NO MES';
    p.txt(MX,y,secLbl,F.b,7,C.textMut); y-=11;
    const BADGES={'alta':{bg:C.altaBg,tx:C.altaTx},'media':{bg:C.medBg,tx:C.medTx},'média':{bg:C.medBg,tx:C.medTx},'baixa':{bg:C.baixaBg,tx:C.baixaTx}};
    demandas.forEach(d=>{
      const b=BADGES[d.urgencia]||BADGES['baixa'];
      const resumo=d.resumo_demanda||d.motivo||'';
      const msgLines=resumo?wrapText(resumo,LG-50):[];
      const msg_h=msgLines.length>0?(12+msgLines.length*12+8):0,card_h=56+msg_h;
      if(y-card_h<45){y=newPage();p.txt(MX,y,secLbl+' (cont.)',F.b,7,C.textMut);y-=11;}
      p.rr(MX,y-card_h,LG,card_h,10,[1,1,1],C.cardBdr);
      p.txt(MX+10,y-16,trunc(d.itemName||'',50),F.b,11,C.textPri);
      const diasNum=Number(d.dias_inativo)||0;
      p.txtR(612-MX-8,y-16,diasNum+(diasNum===1?' dia':' dias'),F.b,11,C.textPri);
      p.txt(MX+10,y-29,trunc(d.devedor||'N/A',30)+'  |  '+(d._setorDisplay||'N/I'),F.n,9,C.textSec);
      // badges
      const PILL_H=13,PILL_Y=y-43,TXT_Y=PILL_Y+PILL_H/2-3;
      let bx=MX+10;
      function drawBadge(label,bg,tx){
        const bw=label.length*7*0.58+14; // estimativa bold 7pt
        p.rr(bx,PILL_Y,bw,PILL_H,PILL_H/2,bg);
        p.txtC(bx+bw/2,TXT_Y,label,F.b,7,tx);
        bx+=bw+6;
      }
      if(d.urgencia&&BADGES[d.urgencia.toLowerCase()]){const{bg,tx}=BADGES[d.urgencia.toLowerCase()];drawBadge(norm(d.urgencia),bg,tx);}
      if(d.resolvida)drawBadge('finalizada',C.finBg,C.finTx);
      p.txtR(612-MX-8,y-36,'Acessar demanda >',F.b,7,C.link);
      const url=d.linkDemanda||'https://contato-serv.monday.com/boards/'+d.boardID+'/pulses/'+d.pulseID;
      p.link(612-MX-110,y-41,110,16,url);
      if(msgLines.length>0){
        const my=y-52,mh=10+msgLines.length*12+6;
        p.rr(MX+8,my-mh,LG-16,mh,5,C.msgBg);
        p.line(MX+8,my-mh+3,MX+8,my-3,C.msgBdr,2.5);
        p.txt(MX+16,my-10,'RESUMO DA DEMANDA',F.b,6,C.msgBdr);
        msgLines.forEach((ln,li)=>{p.txt(MX+16,my-20-li*12,ln,F.n,8,C.textSec);});
      }
      y-=card_h+8;
    });
  }

  drawFooter(p,numPag);
  streams.push(p.build());
  const pdfBuffer=compilar(streams);
  const nomeRem=norm(remetente).replace(/\s+/g,'_');
  const nomeArq='Relatorio_Mensal_'+nomeRem+'_'+norm(mesNome).replace(/\s+/g,'_')+'.pdf';
  output.push({
    json:{temRelatorio:true,tipo:'PDF_MENSAL',nome_arquivo:nomeArq,remetente,totalDemandas:totalDem,totalDevedores:totalDev,resolvidas,taxaResolucao:taxaRes,mediaDias,mesRelatorio:mesNome,remoteJid:resolverJid(remetente,nivel,demandas[0]?demandas[0]._setorDisplay||demandas[0].setorDemandado:'')},
    binary:{data:{data:pdfBuffer.toString('base64'),mimeType:'application/pdf',fileName:nomeArq,fileExtension:'pdf'}}
  });
}

if(output.length===0)return[{json:{temRelatorio:false}}];
return output;

// Converter PDF binário para base64 + repassar dados
return (async () => {
  const items = $input.all();
  const result = [];
  for (let i = 0; i < items.length; i++) {
    const item = items[i];
    let base64PDF = '';
    if (item.binary && item.binary.data) {
      const binaryDataBuffer = await this.helpers.getBinaryDataBuffer(i, 'data');
      base64PDF = binaryDataBuffer.toString('base64');
    }
    result.push({
      json: {
        pdfBase64: base64PDF,
        fileName: item.json.nome_arquivo || 'Relatorio_Mensal.pdf',
        remoteJid: item.json.remoteJid,
        totalDemandas: item.json.totalDemandas,
        remetente: item.json.remetente,
        mesRelatorio: item.json.mesRelatorio,
      }
    });
  }
  return result;
})();

