};

function normalizar(s){return String(s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().trim();}
function capitalizar(s){return String(s).split(' ').map(w=>w.charAt(0).toUpperCase()+w.slice(1).toLowerCase()).join(' ');}
function resolverSetor(d){
  let s=normalizar(d.setorDemandado||'');
  if(s&&mapaLideres[s])return s;
  const nd=normalizar(d.devedor||'');
  for(const[ln,st]of Object.entries(liderParaSetor)){if(nd===ln||nd.includes(ln)||ln.includes(nd))return st;}
  for(const[nf,sf]of Object.entries(funcionarioSetor)){if(nd.includes(normalizar(nf))||normalizar(nf).includes(nd))return normalizar(sf);}
  return '';
}
function resolverSetorDisplay(d){
  const s=resolverSetor(d);if(!s)return'N/I';
  return{'dp':'DP','rh':'RH','ti':'TI','aions':'AIONS'}[s]||capitalizar(s);
}
function determinarRemetente(d){
  const dias=Number(d.dias_inativo)||1,dev=normalizar(d.devedor||''),setor=resolverSetor(d);
  if(dev.includes('joao')&&dev.includes('dr'))return{nome:'Tuca',nivel:'3'};
  const ehL=nomesLideresLista.some(nl=>dev.includes(nl));
  if(ehL){if(dias>=2)return{nome:'Tuca',nivel:'3'};return{nome:'Dr. João',nivel:'2'};}
  if(setor==='comercial'){if(dias>=2)return{nome:'Tuca',nivel:'3'};return{nome:'Dr. João',nivel:'1'};}
  if(dias>=3)return{nome:'Tuca',nivel:'3'};
  if(dias===2)return{nome:'Dr. João',nivel:'2'};
  const lider=setor?(mapaLideres[setor]||'Lider N/I'):'Lider N/I';
  return{nome:lider,nivel:'1'};
}

// LEITURA DOS DADOS
const rawItems=$('Get row(s) - Cobrança Mensal').all();
const vistos=new Set(),cobrancas=[];
for(const item of rawItems){
  const k=String(item.json.pulseID||item.json.id);
  if(!vistos.has(k)){vistos.add(k);cobrancas.push(item.json);}
}
if(cobrancas.length===0)return[{json:{temRelatorio:false}}];

let cp=[];try{cp=$('Get row(s) - Contagem Relatorio').all();}catch(e){}
const cMap={};
for(const r of cp){const n=(r.json.name||r.json.Name||'').trim().toLowerCase();if(n){if(!cMap[n])cMap[n]=0;cMap[n]+=Number(r.json.quantidade)||0;}}

let cdd=[];try{cdd=$('Get row(s) - Contagem Demanda').all();}catch(e){}
const cdMap={};
for(const r of cdd){const pp=String(r.json.pulse||'').trim();if(pp)cdMap[pp]=Number(r.json.quantidade)||0;}

let monit=[];try{monit=$('Get row(s) - Monitoramento').all();}catch(e){}
const pendentesSet=new Set();
for(const m of monit)pendentesSet.add(String(m.json.pulseID));

let hist=[];try{hist=$('Get row(s) - Historico Semanal').all();}catch(e){}

const agora=new Date();
const mesRel=new Date(agora.getFullYear(),agora.getMonth()-1,1);
const mesNome=capitalizar(mesRel.toLocaleDateString('pt-BR',{month:'long',year:'numeric'}));
const mesNum=mesRel.getMonth()+1;
const anoNum=mesRel.getFullYear();

function semanaParaData(semKey){
  const parts=semKey.split('-S');if(parts.length<2)return null;
  const ano=parseInt(parts[0]),sem=parseInt(parts[1]);
  const jan4=new Date(ano,0,4);const dow=jan4.getDay()||7;
  return new Date(jan4.getTime()-(dow-1)*86400000+(sem-1)*7*86400000);
}
function semanaDoMes(semKey){
  const seg=semanaParaData(semKey);if(!seg)return false;
  for(let d=0;d<5;d++){const dia=new Date(seg.getTime()+d*86400000);if(dia.getMonth()+1===mesNum&&dia.getFullYear()===anoNum)return true;}
  return false;
}
function calcDiasNulos(semKey){
  const seg=semanaParaData(semKey);
  if(!seg)return[false,false,false,false,false];
  return Array.from({length:5},(_,d)=>{const dia=new Date(seg.getTime()+d*86400000);return dia.getMonth()+1!==mesNum||dia.getFullYear()!==anoNum;});
}

cobrancas.forEach(d=>{
  d.total_cobracas_devedor=cMap[(d.devedor||'').trim().toLowerCase()]||0;
  d.vezes_cobrado_demanda=cdMap[String(d.pulseID)]||1;
  d.resolvida=!pendentesSet.has(String(d.pulseID));
  d._setorDisplay=resolverSetorDisplay(d);
  if(d.remetente_nome&&d.nivel_escalonamento){d._remetente={nome:d.remetente_nome,nivel:String(d.nivel_escalonamento)};}
  else{d._remetente=determinarRemetente(d);}
});

const grupos={};
for(const d of cobrancas){const k=d._remetente.nome;if(!grupos[k])grupos[k]={demandas:[]};grupos[k].demandas.push(d);}

function calcularPodio(demandas){
  const setorCount={};
  for(const d of demandas){const s=d._setorDisplay||'N/I';setorCount[s]=(setorCount[s]||0)+1;}
  const todosSetores=['DP','Operacional','Compras','Comercial','Financeiro','RH','TI','Contabilidade','Sesmt','Contratos','Marketing','AIONS','Estoque','Fiscal'];
  todosSetores.forEach(s=>{if(!setorCount[s])setorCount[s]=0;});
  const sorted=Object.entries(setorCount).sort((a,b)=>b[1]-a[1]);
  return{top3:sorted.slice(0,3).map(([nome,qtd])=>({nome,qtd})),resto:sorted.slice(3).map(([nome,qtd],i)=>({pos:i+4,nome,qtd}))};
}

function norm(s){return String(s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^\x00-\x7F]/g,'');}
function trunc(s,m){const n=String(s);return n.length<=m?n:n.substring(0,m-2).trimEnd()+'..';}
// rank_fill — porta do Python (por percentual)
function rank_fill(pct){if(pct>=0.7)return[0.788,0.227,0.227];if(pct>=0.4)return[0.831,0.510,0.102];return[0.604,0.624,0.659];}
function wrapText(text,maxW){
  const words=String(text).split(' ');const lines=[];let line='';
  for(const w of words){const t=(line+' '+w).trim();if(t.length*4.2>maxW){if(line)lines.push(line);line=w;}else line=t;}
  if(line)lines.push(line);return lines;
}

function criarGerador(){
  let pdf='%PDF-1.4\n';const objetos=[],offsets={};
  const F={n:'F1',b:'F2'};
  // PALETA — porta 1:1 do Python relatorio_v3.py
  const C={
    bg:[0.925,0.945,0.949],cardBg:[0.969,0.969,0.973],cardBdr:[0.784,0.800,0.839],
    headerBg:[0.051,0.231,0.431],headerTx:[1,1,1],headerSub:[0.784,0.588,0.243],headerPer:[0.690,0.730,0.800],
    kpiNum:[0.051,0.231,0.431],kpiLbl:[0.353,0.380,0.420],
    textPri:[0.102,0.102,0.137],textSec:[0.353,0.380,0.420],textMut:[0.580,0.604,0.639],
    link:[0.051,0.231,0.431],barTrack:[0.847,0.859,0.890],
    msgBg:[0.898,0.910,0.918],msgBdr:[0.051,0.231,0.431],
    green:[0.181,0.541,0.239],red:[0.788,0.227,0.227],
    rowBg:[0.906,0.918,0.929],
    pod1:[0.820,0.090,0.090],pod2:[0.940,0.470,0.030],pod3:[0.840,0.710,0.020],
    pod1bg:[0.980,0.880,0.880],pod1tx:[0.440,0.060,0.060],
    pod2bg:[0.990,0.930,0.840],pod2tx:[0.440,0.220,0.010],
    pod3bg:[0.985,0.960,0.800],pod3tx:[0.400,0.350,0.010],
    evoNormal:[0.604,0.624,0.659],evoGreen:[0.181,0.541,0.239],
    evoRed:[0.788,0.227,0.227],evoGold:[0.722,0.525,0.043],evoDark:[0.478,0.102,0.102],
    altaBg:[0.961,0.816,0.816],altaTx:[0.478,0.122,0.122],
    medBg:[0.980,0.910,0.784],medTx:[0.420,0.290,0.020],
    baixaBg:[0.847,0.929,0.847],baixaTx:[0.122,0.314,0.122],
    finBg:[0.816,0.910,0.961],finTx:[0.039,0.208,0.314],
  };
  const rgb=c=>c[0].toFixed(3)+' '+c[1].toFixed(3)+' '+c[2].toFixed(3);
  const esc=s=>String(s).replace(/[()\\]/g,'\\$&');
  const pa=[];

  function rrPath(x,y,w,h,r){
    const k=0.5523*r;
    return(x+r)+' '+y+' m '+(x+w-r)+' '+y+' l '+(x+w-r+k)+' '+y+' '+(x+w)+' '+(y+r-k)+' '+(x+w)+' '+(y+r)+' c '+(x+w)+' '+(y+h-r)+' l '+(x+w)+' '+(y+h-r+k)+' '+(x+w-r+k)+' '+(y+h)+' '+(x+w-r)+' '+(y+h)+' c '+(x+r)+' '+(y+h)+' l '+(x+r-k)+' '+(y+h)+' '+x+' '+(y+h-r+k)+' '+x+' '+(y+h-r)+' c '+x+' '+(y+r)+' l '+x+' '+(y+r-k)+' '+(x+r-k)+' '+y+' '+(x+r)+' '+y+' c h';
  }

  function pagina(){
    const ops=[];const idx=pa.length;pa.push([]);
    return{
      rr(x,y,w,h,r,cf,cb,sw){
        ops.push('q');const path=rrPath(x,y,w,h,r||8);
        if(cf&&cb)ops.push(rgb(cf)+' rg '+rgb(cb)+' RG '+(sw||0.5)+' w '+path+' B');
        else if(cf)ops.push(rgb(cf)+' rg '+path+' f');
        else if(cb)ops.push(rgb(cb)+' RG '+(sw||0.5)+' w '+path+' S');
        ops.push('Q');
      },
      rect(x,y,w,h,cf){ops.push('q '+rgb(cf)+' rg '+x+' '+y+' '+w+' '+h+' re f Q');},
      pill(x,y,w,h,cf){if(w<1)return;const r=Math.min(h/2,w/2);ops.push('q '+rgb(cf)+' rg '+rrPath(x,y,w,h,r)+' f Q');},
      txt(x,y,t,fonte,tam,cor){ops.push('q BT /'+(fonte||F.n)+' '+(tam||10)+' Tf '+rgb(cor||C.textPri)+' rg '+x+' '+y+' Td ('+esc(t)+') Tj ET Q');},
      txtC(cx,y,t,fonte,tam,cor){const w=String(t).length*(tam||10)*0.48;ops.push('q BT /'+(fonte||F.n)+' '+(tam||10)+' Tf '+rgb(cor||C.textPri)+' rg '+(cx-w/2)+' '+y+' Td ('+esc(t)+') Tj ET Q');},
      txtR(rx,y,t,fonte,tam,cor){const w=String(t).length*(tam||10)*0.48;ops.push('q BT /'+(fonte||F.n)+' '+(tam||10)+' Tf '+rgb(cor||C.textPri)+' rg '+(rx-w)+' '+y+' Td ('+esc(t)+') Tj ET Q');},
      line(x1,y1,x2,y2,cor,sw){ops.push('q '+rgb(cor)+' RG '+(sw||0.5)+' w '+x1+' '+y1+' m '+x2+' '+y2+' l S Q');},
      link(x,y,w,h,url){pa[idx].push('<</Type /Annot /Subtype /Link /Rect ['+x+' '+y+' '+(x+w)+' '+(y+h)+'] /Border [0 0 0] /A <</S /URI /URI ('+url+')>>>>');},
      build(){return ops.join('\n');}
    };
  }

  function addObj(id,c){objetos.push({id,conteudo:c});}
  function compilar(streams){
    const nf=3+streams.length*2;
    addObj(1,'<</Type /Catalog /Pages 2 0 R>>');
    addObj(2,'<</Type /Pages /Kids ['+streams.map((_,i)=>(3+i*2)+' 0 R').join(' ')+'] /Count '+streams.length+'>>');
    streams.forEach((s,i)=>{
      const pid=3+i*2,sid=4+i*2,len=Buffer.byteLength(s,'latin1');
      let ann='';if(pa[i]&&pa[i].length>0)ann=' /Annots [ '+pa[i].join(' ')+' ]';
      addObj(pid,'<</Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Contents '+sid+' 0 R /Resources <</Font <</F1 '+nf+' 0 R /F2 '+(nf+1)+' 0 R>>>>'+ann+'>>');
      addObj(sid,'<</Length '+len+'>>\nstream\n'+s+'\nendstream');
    });
    addObj(nf,'<</Type /Font /Subtype /Type1 /BaseFont /Helvetica /Encoding /WinAnsiEncoding>>');
    addObj(nf+1,'<</Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold /Encoding /WinAnsiEncoding>>');
    objetos.forEach(({id,conteudo})=>{offsets[id]=Buffer.byteLength(pdf,'latin1');pdf+=id+' 0 obj\n'+conteudo+'\nendobj\n';});
    const xp=Buffer.byteLength(pdf,'latin1'),mx=Math.max(...objetos.map(o=>o.id));
    let xref='xref\n0 '+(mx+1)+'\n0000000000 65535 f \n';
    for(let i=1;i<=mx;i++)xref+=(offsets[i]!==undefined?String(offsets[i]).padStart(10,'0'):'0000000000')+' 00000 n \n';
    xref+='trailer\n<</Size '+(mx+1)+' /Root 1 0 R>>\nstartxref\n'+xp+'\n%%EOF';
    return Buffer.from(pdf+xref,'latin1');
  }
  return{pagina,compilar,C,F};
}

// CONSTANTES
// Python: PW=595, PH=842, PAD=22 → JS: PW=612, PH=792, MX=24, LG=564
const MX=24, LG=564, PH_JS=792;


// ══════════════════════════════════════════════
// PREENCHA OS JIDs AQUI
// Grupos:   120363XXXXXXXXX@g.us
// Pessoal:  5592XXXXXXXXX@s.whatsapp.net
// ══════════════════════════════════════════════
const SETOR_GRUPO_MAP_REL = {
  'dp':            'PREENCHER@g.us',
  'operacional':   'PREENCHER@g.us',
  'rh':            'PREENCHER@g.us',
  'financeiro':    'PREENCHER@g.us',
  'ti':            'PREENCHER@g.us',
  'compras':       'PREENCHER@g.us',
  'fiscal':        'PREENCHER@g.us',
  'comercial':     'PREENCHER@g.us',
  'sesmt':         'PREENCHER@g.us',
  'contratos':     'PREENCHER@g.us',
  'contabilidade': 'PREENCHER@g.us',
  'aions':         'PREENCHER@g.us',
  'estoque':       'PREENCHER@g.us',
  'marketing':     'PREENCHER@g.us',
};
const DIRETO_MAP_REL = {
  'Dr. João': 'PREENCHER@s.whatsapp.net',
  'Tuca':     'PREENCHER@s.whatsapp.net',
};
function resolverJid(remetente, nivel, setor) {
  if (DIRETO_MAP_REL[remetente]) return DIRETO_MAP_REL[remetente];
  const s = String(setor||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().trim();
  return SETOR_GRUPO_MAP_REL[s] || 'PREENCHER@g.us';
}

const output=[];

for(const[remetente,grupo]of Object.entries(grupos)){
  const{pagina,compilar,C,F}=criarGerador();
  const streams=[];
  const demandas=grupo.demandas;
  demandas.sort((a,b)=>(Number(b.dias_inativo)||0)-(Number(a.dias_inativo)||0));

  const ehTuca=remetente==='Tuca', ehDrJoao=remetente==='Dr. João';
  const totalDem=demandas.length;
  const totalDev=[...new Set(demandas.map(d=>d.devedor||'N/A'))].length;
  const resolvidas=demandas.filter(d=>d.resolvida).length;
  const taxaRes=totalDem>0?Math.round(resolvidas/totalDem*100):0;
  const mediaDias=totalDem>0?Math.round(demandas.reduce((a,d)=>a+(Number(d.dias_inativo)||0),0)/totalDem*10)/10:0;
  const maxDias=demandas.reduce((a,d)=>Math.max(a,Number(d.dias_inativo)||0),0);

  const histRem=hist
    .filter(h=>String(h.json.remetente||'').trim()===remetente&&semanaDoMes(String(h.json.semana||'')))
    .sort((a,b)=>String(a.json.semana||'').localeCompare(String(b.json.semana||'')));

  const semanasEvo=histRem.map((h,i)=>{
    const semKey=String(h.json.semana||'');
    const nulos=calcDiasNulos(semKey);
    const dias=nulos.map((isNulo,d)=>isNulo?null:Number([h.json.seg,h.json.ter,h.json.qua,h.json.qui,h.json.sex][d])||0);
    return{label:'Sem '+(i+1),dias};
  });
  if(semanasEvo.length===0)for(let i=0;i<4;i++)semanasEvo.push({label:'Sem '+(i+1),dias:[0,0,0,0,0]});

  const podio=(ehDrJoao||ehTuca)?calcularPodio(demandas):null;

  let numPag=1,p=pagina();
  function drawFooter(pg,n){
    pg.txt(MX,12,'Aions Corp — Sistema de cobranca inteligente',F.n,8,C.textMut);
    pg.txtR(612-MX,12,'Pag. '+n,F.n,8,C.textMut);
  }
  function newPage(){drawFooter(p,numPag);streams.push(p.build());numPag++;p=pagina();p.rect(0,0,612,PH_JS,C.bg);return PH_JS-20;}

  p.rect(0,0,612,PH_JS,C.bg);
  let y=PH_JS-20; // y=772

  // HEADER — porta exata do draw_header() Python relatorio_v3.py
  // Card: y-92 a y (680 a 772)
  p.rr(MX,y-92,LG,92,12,C.headerBg);
  // Pill "RELATORIO MENSAL" — topo do card
  {
    const pl='RELATORIO MENSAL',ph=15,pw=pl.length*7*0.60+22;
    const px=306-pw/2;
    p.rr(px,y-18,pw,ph,ph/2,[0.09,0.32,0.58]);
    // txt manual: txtC usa 0.48 (subestima bold caps) → usar 0.60 para centralizar
    const pillTxtW=pl.length*7*0.60;
    p.txt(306-pillTxtW/2,y-18+ph/2-2,pl,F.b,7,[0.60,0.78,0.96]);
  }
  // Nome
  p.txtC(306,y-42,remetente,F.b,19,C.headerTx);
  // Subtítulo
  const sub=ehTuca?'Cobrancas de 3+ dias sem resposta (Nivel 3) — mensal':
             ehDrJoao?'Cobrancas niveis 2 e 3 — visao consolidada do mes':
             'Cobrancas do setor — nivel 1 — visao do mes';
  p.txtC(306,y-60,sub,F.n,9,C.headerSub);
  // Período
  p.txtC(306,y-75,mesNome,F.n,9,C.headerPer);
  y-=106;

  // KPIs — draw_kpis(): kw=(PW-PAD*2-gap*(n-1))/n, kh=62, gap=5
  // txt center: (x+kw/2, y-26, 20bold), (y-41, 8), (y-54, 8bold)
  {
    const gap=5;
    const kpis=ehTuca?
      [[String(totalDem),'Pendencias',false],[String(totalDev),'Devedores',false],[String(mediaDias),'Media dias',false],[String(maxDias),'Max. dias',false]]:
      [[String(totalDem),'Cobrancas',false],[String(totalDev),'Devedores',false],[String(resolvidas),'Finalizadas',true],[taxaRes+'%','Finalizacao',true]];
    const n=kpis.length,kw=(LG-gap*(n-1))/n,kh=62;
    kpis.forEach(([v,l,good],i)=>{
      const x=MX+i*(kw+gap);
      p.rr(x,y-kh,kw,kh,8,C.cardBg,C.cardBdr);
      p.txtC(x+kw/2,y-26,v,F.b,20,good?C.green:C.kpiNum);
      p.txtC(x+kw/2,y-41,l,F.n,8,C.kpiLbl);
    });
    y-=kh+14;
  }

  // PÓDIO — draw_podio(): CARD_H=148, MAX_BAR=72, MIN_FRAC=0.38
  // Python: POD_W=(PW-PAD*2)*0.43=551*0.43=236.9 → JS: LG*0.43=242.5
  // Python: base_y=y-CARD_H+34, col_w=POD_W/3
  // Python: bw=min(col_w-12,48), pill_h=14,pill_w=34, pill_y=base_y-pill_h-3
  if(podio){
    p.txt(MX,y,'TOP SETORES DEVEDORES',F.b,7,C.textMut); y-=11;
    const CARD_H=148,MAX_BAR=72,MIN_FRAC=0.38;
    p.rect(MX,y-CARD_H,LG,CARD_H,C.bg);
    const POD_W=LG*0.43;
    const top3=podio.top3,resto=podio.resto;
    const vals=top3.map(t=>t.qtd),maxV=Math.max(...vals,1),minV=Math.min(...vals,0);
    function scaledH(v){
      if(maxV===minV)return Math.floor(MAX_BAR*0.7);
      return Math.max(Math.floor((MIN_FRAC+(1-MIN_FRAC)*(v-minV)/(maxV-minV))*MAX_BAR),6);
    }
    const ORDER=[1,0,2],BAR_COLS=[C.pod1,C.pod2,C.pod3],B_BG=[C.pod1bg,C.pod2bg,C.pod3bg],B_TX=[C.pod1tx,C.pod2tx,C.pod3tx];
    const col_w=POD_W/3,base_y=y-CARD_H+34;
    ORDER.forEach((orig,slot)=>{
      if(orig>=top3.length)return;
      const{nome,qtd}=top3[orig];
      const cx=MX+8+slot*col_w+col_w/2;
      const bh=scaledH(qtd),bw=Math.min(col_w-12,48),bx=cx-bw/2,bar_top=base_y+bh;
      p.txtC(cx,bar_top+18,String(qtd),F.b,14,C.textPri);
      p.txtC(cx,bar_top+7,'demandas',F.n,7,C.textMut);
      p.rr(bx,base_y,bw,bh,4,BAR_COLS[orig]);
      const pill_h=14,pill_w=34,pill_x=cx-pill_w/2,pill_y=base_y-pill_h-3;
      p.rr(pill_x,pill_y,pill_w,pill_h,pill_h/2,B_BG[orig]);
      p.txtC(cx,pill_y+pill_h/2-3,String(orig+1)+'o',F.b,8,B_TX[orig]);
      p.txtC(cx,pill_y-9,trunc(nome,9),F.n,6,C.textSec);
    });
    const div_x=MX+8+POD_W+10;
    p.line(div_x,y-CARD_H+12,div_x,y-10,C.cardBdr,0.5);
    const lx=div_x+10,row_h=(CARD_H-22)/Math.max(resto.length,1);
    resto.forEach(({pos,nome,qtd},i)=>{
      const ry=y-16-i*row_h;
      p.txt(lx,ry,String(pos)+'o',F.n,7,C.textMut);
      p.txt(lx+18,ry,trunc(nome,18),F.n,8,C.textSec);
      p.txtR(612-MX-8,ry,String(qtd),F.b,8,qtd>0?C.textPri:C.textMut);
      if(i<resto.length-1)p.line(lx,ry-6,612-MX-8,ry-6,C.cardBdr,0.3);
    });
    y-=CARD_H+12;
  }

  // RANKINGS — draw_rankings(): gap=8, half=(PW-PAD*2-gap)/2=271.5 → JS: (LG-8)/2=278
  // tw=half-108=163.5 → 170, bx=cx+half-tw-20=cx+88 (mesmo!)
  // card_h=20+n*19+8, ry=y-26-i*19
  {
    const gap=8,half=(LG-gap)/2; // 278
    const rq={};demandas.forEach(d=>{const dev=d.devedor||'N/A';rq[dev]=(rq[dev]||0)+1;});
    const tq=Object.entries(rq).sort((a,b)=>b[1]-a[1]).slice(0,5);
    const mxq=tq[0]?tq[0][1]:1;
    const rd={};demandas.forEach(d=>{const dev=d.devedor||'N/A';const dias=Number(d.dias_inativo)||0;if(!rd[dev]||dias>rd[dev])rd[dev]=dias;});
    const td=Object.entries(rd).sort((a,b)=>b[1]-a[1]).slice(0,5);
    const mxd=td[0]?td[0][1]:1;
    const n=Math.max(tq.length,td.length),card_h=20+n*19+8;
    if(y-card_h<40)y=newPage();
    [[tq,mxq,''],[td,mxd,'d']].forEach(([data,mv,suf],col)=>{
      const cx=MX+col*(half+gap);
      p.rr(cx,y-card_h,half,card_h,8,C.cardBg,C.cardBdr);
      p.txt(cx+10,y-12,col===0?'POR QUANTIDADE':'POR DIAS PARADO',F.b,9,C.textMut);
      const tw=half-108; // 170px — barra começa em cx+88, termina em cx+258, card=278 ✓
      data.forEach(([nome,val],i)=>{
        const ry=y-26-i*19;
        p.txt(cx+10,ry,trunc(nome,15),F.n,9,C.textPri);
        p.pill(cx+half-tw-20,ry-2,tw,7,C.barTrack);
        p.pill(cx+half-tw-20,ry-2,Math.max(tw*(val/mv),4),7,rank_fill(val/mv));
        p.txtR(cx+half-6,ry,String(val)+suf,F.b,9,C.textPri);
      });
    });
    y-=card_h+12;
  }

  // EVOLUÇÃO SEMANAL — draw_evolucao()
  // Python: ROW_H=100, LABEL_W=42, INNER_PAD=14, MAX_BAR=58, NUM_Y_OFF=14, NAME_GAP=9
  // Python: avail_w=PW-PAD*2-LABEL_W-INNER_PAD*2, col_w=avail_w/5
  // Python: baseline=y-ROW_H+20, bw=col_w*0.72
  {
    p.txt(MX,y,'EVOLUCAO SEMANAL',F.b,7,C.textMut); y-=10;
    // legenda — rr(lx,y-8,8,8,1,cor), txt(lx+11,y-1,nm,7), lx+=len*4.2+20
    const legItems=[['Normal',C.evoNormal],['Menor da semana',C.evoGreen],['Maior da semana',C.evoRed],['Menor do mes',C.evoGold],['Maior do mes',C.evoDark],['Fora do mes',[0.75,0.77,0.80]]];
    let lx=MX;
    legItems.forEach(([nm,cor])=>{
      p.rr(lx,y-8,8,8,1,cor);                  // quadrado: centro em y-4
      p.txt(lx+11,y-7,nm,F.n,7,C.textMut);   // baseline y-7 → centro visual y-4.5
      lx+=nm.length*4.2+20;
    });
    y-=18;

    const ativos=semanasEvo.flatMap(s=>s.dias.filter(v=>v!==null));
    // g_max nunca pode ser 0 — 0/0=NaN gera coordenadas inválidas no PDF
    const _gmax=ativos.length?Math.max(...ativos):0;
    const g_max=_gmax>0?_gmax:1;
    const g_min=ativos.length?Math.min(...ativos):0;
    const ROW_H=100,LABEL_W=42,INNER_PAD=14,MAX_BAR=58,NUM_Y_OFF=14,NAME_GAP=9;
    const avail_w=LG-LABEL_W-INNER_PAD*2,col_w=avail_w/5;
    const DIAS=['Seg','Ter','Qua','Qui','Sex'];

    semanasEvo.forEach(sem=>{
      if(y-ROW_H-10<40)y=newPage();
      p.rr(MX,y-ROW_H,LG,ROW_H,30,C.rowBg,C.cardBdr,0.4);
      // "Sem X" centrado vertical (ROW_H/2) e horizontal (LABEL_W/2) na coluna esquerda
      p.txtC(MX+LABEL_W/2,y-ROW_H/2-3,sem.label,F.n,8,C.textMut);
      const vals=sem.dias.filter(v=>v!==null);
      const s_min=vals.length?Math.min(...vals):0,s_max=vals.length?Math.max(...vals):1;
      const baseline=y-ROW_H+20;
      sem.dias.forEach((val,i)=>{
        const cx=MX+LABEL_W+INNER_PAD+i*col_w+col_w/2,bw=col_w*0.72,bx=cx-bw/2;
        if(val===null){
          p.rr(bx,baseline,bw,16,3,[0.80,0.82,0.84]);
          p.txtC(cx,baseline+16+NAME_GAP,DIAS[i],F.b,9,[0.72,0.74,0.78]);
          p.txtC(cx,baseline-NUM_Y_OFF+4,'—',F.n,9,[0.72,0.74,0.78]);
        }else{
          let bc,nc;
          if(g_max>0&&val===g_max&&g_max!==g_min){bc=C.evoDark;nc=C.evoDark;}
          else if(g_max>0&&val===g_min&&g_min!==g_max){bc=C.evoGold;nc=C.evoGold;}
          else if(s_max>0&&val===s_max){bc=C.evoRed;nc=C.evoRed;}
          else if(s_max>0&&val===s_min&&s_min!==s_max){bc=C.evoGreen;nc=C.evoGreen;}
          else{bc=C.evoNormal;nc=C.textSec;}
          const bh=val>0?Math.max(Math.floor((val/g_max)*MAX_BAR),5):0;
          if(bh>0){
            p.txtC(cx,baseline+bh+NAME_GAP+2,String(val),F.b,11,nc);
            p.rr(bx,baseline,bw,bh,4,bc);
          } else {
            // valor zero: stub mínimo + número no topo
            p.rr(bx,baseline,bw,4,2,C.evoNormal);
            p.txtC(cx,baseline+4+NAME_GAP,String(val),F.n,9,C.textSec);
          }
          p.txtC(cx,baseline-NUM_Y_OFF,DIAS[i],F.b,9,C.textSec);
        }
      });
      y-=ROW_H+8;
    });
    y-=4;
  }

  // DEMANDAS — draw_demanda(): card_h=56+msg_h, rr fill=(1,1,1)
  // txt(PAD+10,y-16,11bold), txtR(PW-PAD-8,y-16,11bold)
  // txt(PAD+10,y-29,9), PILL_H=13,PILL_Y=y-43,TXT_Y=PILL_Y+PILL_H/2-3
  // txtR(PW-PAD-8,y-36,'Acessar demanda >',7bold)
  // my=y-52, mh=10+len*12+6
  {
    if(y-80<40)y=newPage();
    const secLbl=ehTuca?'DEMANDAS CRITICAS DO MES':'DEMANDAS COBRADAS NO MES';
    p.txt(MX,y,secLbl,F.b,7,C.textMut); y-=11;
    const BADGES={'alta':{bg:C.altaBg,tx:C.altaTx},'media':{bg:C.medBg,tx:C.medTx},'média':{bg:C.medBg,tx:C.medTx},'baixa':{bg:C.baixaBg,tx:C.baixaTx}};
    demandas.forEach(d=>{
      const b=BADGES[d.urgencia]||BADGES['baixa'];
      const resumo=d.resumo_demanda||d.motivo||'';
      const msgLines=resumo?wrapText(resumo,LG-50):[];
      const msg_h=msgLines.length>0?(12+msgLines.length*12+8):0,card_h=56+msg_h;
      if(y-card_h<45){y=newPage();p.txt(MX,y,secLbl+' (cont.)',F.b,7,C.textMut);y-=11;}
      p.rr(MX,y-card_h,LG,card_h,10,[1,1,1],C.cardBdr);
      p.txt(MX+10,y-16,trunc(d.itemName||'',50),F.b,11,C.textPri);
      const diasNum=Number(d.dias_inativo)||0;
      p.txtR(612-MX-8,y-16,diasNum+(diasNum===1?' dia':' dias'),F.b,11,C.textPri);
      p.txt(MX+10,y-29,trunc(d.devedor||'N/A',30)+'  |  '+(d._setorDisplay||'N/I'),F.n,9,C.textSec);
      // badges
      const PILL_H=13,PILL_Y=y-43,TXT_Y=PILL_Y+PILL_H/2-3;
      let bx=MX+10;
      function drawBadge(label,bg,tx){
        const bw=label.length*7*0.58+14; // estimativa bold 7pt
        p.rr(bx,PILL_Y,bw,PILL_H,PILL_H/2,bg);
        p.txtC(bx+bw/2,TXT_Y,label,F.b,7,tx);
        bx+=bw+6;
      }
      if(d.urgencia&&BADGES[d.urgencia.toLowerCase()]){const{bg,tx}=BADGES[d.urgencia.toLowerCase()];drawBadge(norm(d.urgencia),bg,tx);}
      if(d.resolvida)drawBadge('finalizada',C.finBg,C.finTx);
      p.txtR(612-MX-8,y-36,'Acessar demanda >',F.b,7,C.link);
      const url=d.linkDemanda||'https://contato-serv.monday.com/boards/'+d.boardID+'/pulses/'+d.pulseID;
      p.link(612-MX-110,y-41,110,16,url);
      if(msgLines.length>0){
        const my=y-52,mh=10+msgLines.length*12+6;
        p.rr(MX+8,my-mh,LG-16,mh,5,C.msgBg);
        p.line(MX+8,my-mh+3,MX+8,my-3,C.msgBdr,2.5);
        p.txt(MX+16,my-10,'RESUMO DA DEMANDA',F.b,6,C.msgBdr);
        msgLines.forEach((ln,li)=>{p.txt(MX+16,my-20-li*12,ln,F.n,8,C.textSec);});
      }
      y-=card_h+8;
    });
  }

  drawFooter(p,numPag);
  streams.push(p.build());
  const pdfBuffer=compilar(streams);
  const nomeRem=norm(remetente).replace(/\s+/g,'_');
  const nomeArq='Relatorio_Mensal_'+nomeRem+'_'+norm(mesNome).replace(/\s+/g,'_')+'.pdf';
  output.push({
    json:{temRelatorio:true,tipo:'PDF_MENSAL',nome_arquivo:nomeArq,remetente,totalDemandas:totalDem,totalDevedores:totalDev,resolvidas,taxaResolucao:taxaRes,mediaDias,mesRelatorio:mesNome,remoteJid:resolverJid(remetente,nivel,demandas[0]?demandas[0]._setorDisplay||demandas[0].setorDemandado:'')},
    binary:{data:{data:pdfBuffer.toString('base64'),mimeType:'application/pdf',fileName:nomeArq,fileExtension:'pdf'}}
  });
}

if(output.length===0)return[{json:{temRelatorio:false}}];
return output;

// Converter PDF binário para base64 + repassar dados
return (async () => {
  const items = $input.all();
  const result = [];
  for (let i = 0; i < items.length; i++) {
    const item = items[i];
    let base64PDF = '';
    if (item.binary && item.binary.data) {
      const binaryDataBuffer = await this.helpers.getBinaryDataBuffer(i, 'data');
      base64PDF = binaryDataBuffer.toString('base64');
    }
    result.push({
      json: {
        pdfBase64: base64PDF,
        fileName: item.json.nome_arquivo || 'Relatorio_Mensal.pdf',
        remoteJid: item.json.remoteJid,
        totalDemandas: item.json.totalDemandas,
        remetente: item.json.remetente,
        mesRelatorio: item.json.mesRelatorio,
      }
    });
  }
  return result;
})();

