const currentItemId = String(prep.monday_item_id || '');
const items = response.data?.items_page_by_column_values?.items || [];

let conflito = null;
for (const item of items) {
  if (String(item.id) === currentItemId) continue;

  const cols = colsOf(item);
  const existingIdentity = currentHasChapa
    ? normCode(cols[COL.CHAPA])
    : normName(cols[COL.NOME_EMPREGADO] || item.name);
  if (!existingIdentity || existingIdentity !== currentIdentity) continue;

  const periodo = effectivePeriod(
    cols[COL.DATA_INICIO],
    cols[COL.DATA_FIM],
    cols[COL.STATUS_CONVOCACAO],
    cols[COL.CANCELAMENTO_INICIO]
  );
  if (!periodo) continue;
  if (!overlaps(periodo.start, periodo.end, prep.data_inicio, prep.data_fim)) continue;

  conflito = {
    item_id: String(item.id),
    item_url: 'https://contato-serv.monday.com/boards/18408773953/pulses/' + item.id,
    nome: item.name,
    chapa: cols[COL.CHAPA] || '',
    data_inicio: periodo.start,
    data_fim: periodo.end,
    data_inicio_original: cols[COL.DATA_INICIO] || '',
    data_fim_original: cols[COL.DATA_FIM] || '',
    status_convocacao: cols[COL.STATUS_CONVOCACAO] || '',
    data_inicio_cancelamento: cols[COL.CANCELAMENTO_INICIO] || ''
  };
  break;
}

if (conflito) {
  return [{
    json: {
      ...prep,

      semConflito: false,

      conflito,
      column_values_conflito_json: JSON.stringify({
        color_mm3a8ana: { label: 'Bloqueada - conflito' },
        link_mm2pn9kg: { url: conflito.item_url, text: 'Conflito: ver convocacao existente' }
      })
    }
  }];
}

return [{ json: { ...prep, semConflito: true } }];

