function normalizar(s){return String(s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().trim();}
function capitalizar(s){return String(s).split(' ').map(w=>w.charAt(0).toUpperCase()+w.slice(1).toLowerCase()).join(' ');}

function resolverSetor(d){
  // PRIORIDADE: Setor da PESSOA (devedor) — mais preciso que o setor da demanda
  const nd=normalizar(d.devedor||'');

  if(nd){
    // 1. Verifica se o devedor é um líder
    for(const[liderNorm,setor]of Object.entries(liderParaSetor)){
      if(nd===liderNorm)return setor;
      if(nd.length>=4&&(nd.includes(liderNorm)||liderNorm.includes(nd)))return setor;
    }
    // 2. Busca pelo nome do funcionário no mapa
    for(const[nf,sf]of Object.entries(funcionarioSetor)){
      const nfn=normalizar(nf);
      if(nd===nfn)return normalizar(sf);
      if(nd.length>=4&&(nd.includes(nfn)||nfn.includes(nd)))return normalizar(sf);
    }
  }

  // 3. Fallback: setor da demanda
  const s=normalizar(d.setorDemandado||'');
  if(s&&mapaLideres[s])return s;

  return '';
}
function resolverSetorDisplay(d){
  const s=resolverSetor(d);if(!s)return'N/I';
  const m={'dp':'DP','rh':'RH','ti':'TI','aions':'AIONS'};
  return m[s]||capitalizar(s);
}
function determinarRemetente(d){
  const dias=Number(d.dias_inativo)||1,dev=normalizar(d.devedor||''),setor=resolverSetor(d);
  if(dev.includes('joao')&&dev.includes('dr'))return{nome:'Tuca',nivel:'3',tipo:'TUCA',subtitulo:'Demandas críticas paradas há 3+ dias'};
  const ehL=nomesLideresLista.some(nl=>dev.includes(nl));
  if(ehL){if(dias>=2)return{nome:'Tuca',nivel:'3',tipo:'TUCA',subtitulo:'Líderes sem resposta há 2+ dias'};return{nome:'Dr. João',nivel:'2',tipo:'DR. JOAO',subtitulo:'Líderes com demanda pendente há 24h'};}
  if(setor==='comercial'){if(dias>=2)return{nome:'Tuca',nivel:'3',tipo:'TUCA',subtitulo:'Comercial — demandas paradas há 2+ dias'};return{nome:'Dr. João',nivel:'1',tipo:'DR. JOAO',subtitulo:'Comercial — demandas pendentes há 24h'};}
  if(dias>=3)return{nome:'Tuca',nivel:'3',tipo:'TUCA',subtitulo:'Demandas críticas paradas há 3+ dias'};
  if(dias===2)return{nome:'Dr. João',nivel:'2',tipo:'DR. JOAO',subtitulo:'Demandas sem resposta há 2 dias'};
  const lider=setor?(mapaLideres[setor]||'Lider N/I'):'Lider N/I';
  return{nome:lider,nivel:'1',tipo:'LIDER',subtitulo:'Demandas pendentes há 24 horas'};
}

