// == PDF ENGINE with rounded rects ==
function norm(s){return String(s).normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^\x00-\x7F]/g,'');}
function trunc(s,m){const n=String(s);return n.length<=m?n:n.substring(0,m-3).trimEnd()+'...';}
function rankColor(v){v=Number(v);if(v>=5)return[0.55,0.10,0.10];if(v>=3)return[0.80,0.20,0.20];if(v===2)return[0.83,0.44,0.13];return[0.80,0.63,0.13];}

function criarGerador(){
  let pdf='%PDF-1.4\n';
  const objetos=[],offsets={};
  const F={n:'F1',b:'F2'};
  const C={
    bg:[0.925,0.945,0.949],cardBg:[0.97,0.97,0.98],cardBdr:[0.78,0.80,0.84],
    headerBg:[0.051,0.231,0.431],headerTx:[1,1,1],headerSub:[0.784,0.588,0.243],
    kpiBg:[0.97,0.97,0.98],kpiNum:[0.051,0.231,0.431],kpiLabel:[0.35,0.38,0.42],highlight:[0.784,0.588,0.243],
    textPri:[0.12,0.12,0.14],textSec:[0.35,0.38,0.42],textMut:[0.50,0.52,0.56],
    link:[0.051,0.231,0.431],barTrack:[0.85,0.87,0.90],
    msgBg:[0.902,0.914,0.918],msgBdr:[0.051,0.231,0.431],msgLabel:[0.051,0.231,0.431],
    bAltaBg:[0.95,0.85,0.85],bAltaTx:[0.55,0.15,0.15],
    bMediaBg:[0.97,0.92,0.80],bMediaTx:[0.50,0.38,0.05],
    bBaixaBg:[0.85,0.93,0.85],bBaixaTx:[0.15,0.40,0.15],
  };
  const rgb=c=>c[0].toFixed(3)+' '+c[1].toFixed(3)+' '+c[2].toFixed(3);
  const esc=s=>String(s).replace(/[()\\]/g,'\\$&');
  const pa=[];

  // Rounded rect path using bezier curves
  function rrPath(x,y,w,h,r){
    const k=0.5523*r;
    return(x+r)+' '+y+' m '
      +(x+w-r)+' '+y+' l '
      +(x+w-r+k)+' '+y+' '+(x+w)+' '+(y+r-k)+' '+(x+w)+' '+(y+r)+' c '
      +(x+w)+' '+(y+h-r)+' l '
      +(x+w)+' '+(y+h-r+k)+' '+(x+w-r+k)+' '+(y+h)+' '+(x+w-r)+' '+(y+h)+' c '
      +(x+r)+' '+(y+h)+' l '
      +(x+r-k)+' '+(y+h)+' '+x+' '+(y+h-r+k)+' '+x+' '+(y+h-r)+' c '
      +x+' '+(y+r)+' l '
      +x+' '+(y+r-k)+' '+(x+r-k)+' '+y+' '+(x+r)+' '+y+' c h';
  }

  function pagina(){
    const ops=[];const idx=pa.length;pa.push([]);
    return{
      // Rounded rect with fill and/or stroke
      rr(x,y,w,h,r,cf,cb,sw){
        ops.push('q');
        const path=rrPath(x,y,w,h,r||8);
        if(cf&&cb){
          ops.push(rgb(cf)+' rg '+rgb(cb)+' RG '+(sw||0.5)+' w '+path+' B');
        }else if(cf){
          ops.push(rgb(cf)+' rg '+path+' f');
        }else if(cb){
          ops.push(rgb(cb)+' RG '+(sw||0.5)+' w '+path+' S');
        }
        ops.push('Q');
      },
      // Simple rect (for page bg)
      rect(x,y,w,h,cf){
        ops.push('q '+rgb(cf)+' rg '+x+' '+y+' '+w+' '+h+' re f Q');
      },
      // Rounded bar (pill shape for progress bars and accent bars)
      pill(x,y,w,h,cf){
        if(w<1)return;
        const r=Math.min(h/2,w/2);
        ops.push('q '+rgb(cf)+' rg '+rrPath(x,y,w,h,r)+' f Q');
      },
      txt(x,y,t,fonte,tam,cor){
        ops.push('q BT /'+(fonte||F.n)+' '+(tam||10)+' Tf '+rgb(cor||C.textPri)+' rg '+x+' '+y+' Td ('+esc(t)+') Tj ET Q');
      },
      txtC(cx,y,t,fonte,tam,cor){
        // Center text at cx
        const w=String(t).length*(tam||10)*0.48;
        const x=cx-w/2;
        ops.push('q BT /'+(fonte||F.n)+' '+(tam||10)+' Tf '+rgb(cor||C.textPri)+' rg '+x+' '+y+' Td ('+esc(t)+') Tj ET Q');
      },
      link(x,y,w,h,url){pa[idx].push('<</Type /Annot /Subtype /Link /Rect ['+x+' '+y+' '+(x+w)+' '+(y+h)+'] /Border [0 0 0] /A <</S /URI /URI ('+url+')>>>>')},
      build(){return ops.join('\n');}
    };
  }
  function addObj(id,c){objetos.push({id,conteudo:c});}
  function compilar(streams){
    const nf=3+streams.length*2;
    addObj(1,'<</Type /Catalog /Pages 2 0 R>>');
    addObj(2,'<</Type /Pages /Kids ['+streams.map((_,i)=>(3+i*2)+' 0 R').join(' ')+'] /Count '+streams.length+'>>');
    streams.forEach((s,i)=>{
      const pid=3+i*2,sid=4+i*2,len=Buffer.byteLength(s,'latin1');
      let ann='';if(pa[i]&&pa[i].length>0)ann=' /Annots [ '+pa[i].join(' ')+' ]';
      addObj(pid,'<</Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Contents '+sid+' 0 R /Resources <</Font <</F1 '+nf+' 0 R /F2 '+(nf+1)+' 0 R>>>>'+ann+'>>');
      addObj(sid,'<</Length '+len+'>>\nstream\n'+s+'\nendstream');
    });
    addObj(nf,'<</Type /Font /Subtype /Type1 /BaseFont /Helvetica /Encoding /WinAnsiEncoding>>');
    addObj(nf+1,'<</Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold /Encoding /WinAnsiEncoding>>');
    objetos.forEach(({id,conteudo})=>{offsets[id]=Buffer.byteLength(pdf,'latin1');pdf+=id+' 0 obj\n'+conteudo+'\nendobj\n';});
    const xp=Buffer.byteLength(pdf,'latin1'),mx=Math.max(...objetos.map(o=>o.id));
    let xref='xref\n0 '+(mx+1)+'\n0000000000 65535 f \n';
    for(let i=1;i<=mx;i++)xref+=(offsets[i]!==undefined?String(offsets[i]).padStart(10,'0'):'0000000000')+' 00000 n \n';
    xref+='trailer\n<</Size '+(mx+1)+' /Root 1 0 R>>\nstartxref\n'+xp+'\n%%EOF';
    return Buffer.from(pdf+xref,'latin1');
  }
  return{pagina,compilar,C,F};
}

function wrapText(text,maxW){
  const words=String(text).split(' ');const lines=[];let line='';
  for(const w of words){const t=(line+' '+w).trim();if(t.length*4.2>maxW){if(line)lines.push(line);line=w;}else line=t;}
  if(line)lines.push(line);return lines;
}

// == GENERATE ==
const agora=new Date();
const dataFmt=agora.toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit',year:'numeric'});
const output=[];

for(const[remetente,grupo]of Object.entries(grupos)){
  const{pagina,compilar,C,F}=criarGerador();
  const streams=[];
  const MX=24,LG=564;
  const tipoInfo=grupo.info;
  const demandas=grupo.demandas;
  demandas.sort((a,b)=>(Number(b.dias_inativo)||0)-(Number(a.dias_inativo)||0));
  const totalDem=demandas.length;
  const totalDev=[...new Set(demandas.map(d=>d.devedor||'N/A'))].length;
  const mediaDias=totalDem>0?(demandas.reduce((a,d)=>a+(Number(d.dias_inativo)||0),0)/totalDem).toFixed(1):'0';
  const maxDias=demandas.reduce((a,d)=>Math.max(a,Number(d.dias_inativo)||0),0);

  let numPag=1,p=pagina();

  const badge={
    'alta':{bg:C.bAltaBg,tx:C.bAltaTx},
    'media':{bg:C.bMediaBg,tx:C.bMediaTx},
    'baixa':{bg:C.bBaixaBg,tx:C.bBaixaTx},
  };

  function drawHeader(pg,y){
    pg.rect(0,0,612,792,C.bg);
    // Card header maior para acomodar o novo layout
    pg.rr(20,y-96,572,96,12,C.headerBg);
    // Estilo idêntico ao semanal: "Nome — Relatório diário" em texto grande
    pg.txtC(306,y-38,remetente+' — Relatório diário',F.b,22,C.headerTx);
    // Subtítulo
    pg.txtC(306,y-60,tipoInfo.subtitulo,F.n,10,C.headerSub);
    // Data
    pg.txtC(306,y-76,dataFmt,F.n,9,[0.55,0.65,0.78]);
  }

  function drawFooter(pg,n){
    pg.txt(24,18,'Aions Corp — Sistema de cobrança inteligente',F.n,8,C.textMut);
    pg.txt(540,18,'Pag. '+n,F.n,8,C.textMut);
  }

  function newPage(){
    drawFooter(p,numPag);streams.push(p.build());numPag++;p=pagina();
    p.rect(0,0,612,792,C.bg);
    return 760;
  }

  drawHeader(p,792-20);
  let y=792-20-116;

  // KPIs
  const ehTuca=remetente==='Tuca';
  const kpis=[[String(totalDem),'Demandas',false],[String(totalDev),'Devedores',false]];
  if(ehTuca){kpis.push([mediaDias,'Média dias',false]);kpis.push([String(maxDias),'Máx. dias',true]);}
  const kw=(LG-30)/kpis.length;
  kpis.forEach(([v,l,hl],i)=>{
    const kx=MX+i*(kw+10);
    if(hl){p.rr(kx,y-52,kw,52,10,C.kpiBg,C.highlight,1.5);}
    else{p.rr(kx,y-52,kw,52,10,C.kpiBg,C.cardBdr);}
    p.txtC(kx+kw/2,y-24,v,F.b,22,C.kpiNum);
    p.txtC(kx+kw/2,y-42,l,F.n,9,C.kpiLabel);
  });
  y-=72;

  p.txt(MX,y,'DEMANDAS PENDENTES',F.b,10,C.textMut);
  y-=16;

  // Cards
  demandas.forEach((d,idx)=>{
    const b=badge[d.urgencia]||badge['baixa'];
    const resumo=d.resumo_demanda||d.motivo||'';
    // maxW conservador: box tem 540px, texto começa em x=46 com 10px de margem dir → 484px disponíveis
    // Usando 440 como margem extra para evitar overflow mesmo com chars largos
    const msgLines=resumo?wrapText(resumo,440):[];
    const cardH=58+(msgLines.length>0?22+msgLines.length*14+14:0);

    if(y-cardH<50){
      y=newPage();
      p.txt(MX,y,'DEMANDAS PENDENTES (cont.)',F.b,10,C.textMut);
      y-=16;
    }

    // Card with rounded corners
    p.rr(MX,y-cardH,LG,cardH,10,C.cardBg,C.cardBdr);

    // Row 1: Name + Dias
    p.txt(36,y-18,trunc(d.itemName||'',42),F.b,12,C.textPri);
    const diasNum=Number(d.dias_inativo)||0;p.txt(520,y-18,diasNum+(diasNum===1?' dia':' dias'),F.b,12,C.textPri);

    // Row 2: Devedor | Setor  [badge]    Acessar ->
    const devStr=trunc(d.devedor||'N/A',25);
    const setorD=resolverSetorDisplay(d);
    const infoStr=devStr+'  |  '+setorD;
    p.txt(36,y-35,infoStr,F.n,10,C.textSec);

    // Badge (rounded pill) — centralizado horizontal e verticalmente
    const urgText=norm(d.urgencia||'baixa');
    const infoW=infoStr.length*5;
    const bx=36+infoW+10;
    const pillW=urgText.length*6+18;
    const pillH=14;
    const pillY=y-40;
    p.rr(bx,pillY,pillW,pillH,pillH/2,b.bg);
    p.txtC(bx+pillW/2,pillY+pillH/2-2.5,urgText,F.b,8,b.tx);

    // Link
    const url=d.linkDemanda||'https://contato-serv.monday.com/boards/'+d.boardID+'/pulses/'+d.pulseID;
    p.txt(480,y-35,'Acessar demanda →',F.b,8,C.link);
    p.link(478,y-40,110,16,url);

    // Resumo box
    if(msgLines.length>0){
      const mh=20+msgLines.length*14+6;
      const my=y-54;
      // Box da margem esquerda do card com padding
      p.rr(MX+8,my-mh,LG-16,mh,6,C.msgBg);
      // Accent bar lateral azul
      p.pill(MX+8,my-mh+4,3,mh-8,C.msgBdr);
      p.txt(MX+18,my-12,'RESUMO DA DEMANDA',F.b,7,C.msgLabel);
      msgLines.forEach((ln,li)=>{
        p.txt(MX+18,my-26-li*14,ln,F.n,9,C.textSec);
      });
    }

    y-=cardH+10;
  });

  // Rankings
  y-=14;
  if(y-160<50){y=newPage();}

  p.txt(MX,y,'TOP DEVEDORES (POR QUANTIDADE)',F.b,10,C.textMut);
  y-=18;

  const rq={};demandas.forEach(d=>{const dev=d.devedor||'N/A';rq[dev]=(rq[dev]||0)+1;});
  const tq=Object.entries(rq).sort((a,b)=>b[1]-a[1]).slice(0,5);
  const mxq=tq[0]?tq[0][1]:1;

  tq.forEach(([name,val])=>{
    p.txt(MX,y,trunc(name,28),F.n,10,C.textPri);
    const bx=200,bw=300;
    p.pill(bx,y-2,bw,8,C.barTrack);
    p.pill(bx,y-2,Math.max(bw*(val/mxq),6),8,rankColor(val));
    p.txt(520,y,String(val),F.b,10,C.textPri);
    y-=22;
  });

  y-=10;
  if(y-120<50){y=newPage();}

  p.txt(MX,y,'TOP DEVEDORES (POR DIAS PARADO)',F.b,10,C.textMut);
  y-=18;

  const rd={};demandas.forEach(d=>{const dev=d.devedor||'N/A';const dias=Number(d.dias_inativo)||0;if(!rd[dev]||dias>rd[dev])rd[dev]=dias;});
  const td=Object.entries(rd).sort((a,b)=>b[1]-a[1]).slice(0,5);
  const mxd=td[0]?td[0][1]:1;

  td.forEach(([name,val])=>{
    p.txt(MX,y,trunc(name,28),F.n,10,C.textPri);
    const bx=200,bw=300;
    p.pill(bx,y-2,bw,8,C.barTrack);
    p.pill(bx,y-2,Math.max(bw*(val/mxd),6),8,rankColor(val));
    p.txt(520,y,val+'d',F.b,10,C.textPri);
    y-=22;
  });

  drawFooter(p,numPag);streams.push(p.build());

  const pdfBuffer=compilar(streams);
  const nomeRem=norm(remetente).replace(/\s+/g,'_');
  const nomeArq='Relatorio_'+nomeRem+'_'+norm(dataFmt).replace(/\//g,'-')+'.pdf';

  output.push({
    json:{
      temRelatorio:true,nome_arquivo:nomeArq,remetente,
      tipoRelatorio:tipoInfo.tipo,nivel:tipoInfo.nivel,
      totalDemandas:totalDem,totalDevedores:totalDev,
      // remoteJid será definido pelo node 'Roteador do Relatório'
    },
    binary:{
      data:{data:pdfBuffer.toString('base64'),mimeType:'application/pdf',fileName:nomeArq,fileExtension:'pdf'}
    }
  });
}

if(output.length===0)return[{json:{temRelatorio:false}}];
return output;

