// Roteador do Relatório — define o remoteJid de cada PDF antes do envio via Evolution API
// Tuca / Dr. João → número pessoal
// Líderes → grupo do setor do remetente

// ══════════════════════════════════════════════
// PREENCHA OS JIDs AQUI
// Grupos:   120363XXXXXXXXX@g.us
// Pessoal:  5592XXXXXXXXX (sem @s.whatsapp.net — Evolution adiciona)
// ══════════════════════════════════════════════

const LIDER_GRUPO_MAP = {
  'Odney':             '120363424978312590@g.us',  // grupo DP
  'Ariana':            '120363424978312590@g.us',  // grupo Financeiro
  'Rainer':            '120363424978312590@g.us',  // grupo RH
  'Rayro':             '120363424978312590@g.us',  // grupo TI
  'Aleane':            '120363424978312590@g.us',  // grupo Marketing
  'Jessica':           '120363424978312590@g.us',  // grupo Sesmt
  'Vinicius':          '120363424978312590@g.us',  // grupo Compras
  'Karine':            '120363424978312590@g.us',  // grupo Contabilidade/Fiscal
  'Karlla':            '120363424978312590@g.us',  // grupo Operacional
  'Karen Vasconcelos': '120363424978312590@g.us',  // grupo AIONS
  'Jeferson':          '120363424978312590@g.us',  // grupo Contratos
  'Ernandes':          '120363424978312590@g.us',  // grupo Estoque
};

const DIRETO_MAP = {
  'Tuca':     '559293937174',
  'Dr. João': '559284101898',
};

const FALLBACK_GRUPO = '120363424978312590@g.us';

return $input.all().map(item => {
  const remetente = String(item.json.remetente || '').trim();

  let remoteJid;
  let destinoTipo;

  if (DIRETO_MAP[remetente]) {
    remoteJid   = DIRETO_MAP[remetente];
    destinoTipo = 'pessoal';
  } else if (LIDER_GRUPO_MAP[remetente]) {
