    destinoTipo = 'grupo';
  } else {
    remoteJid   = FALLBACK_GRUPO;
    destinoTipo = 'fallback';
  }

  return {
    json: { ...item.json, remoteJid, destinoTipo }
  };
});

const BOARD_SOLICITACAO = 18393673859;

let dados;
try {
  dados = $('Code in JavaScript8').first().json;
} catch (e) {
  throw new Error('Code in JavaScript8 not found');
}

const boletoVR = Number(dados.boletoVR || 0);
const boletoVT = Number(dados.boletoVT || 0);

if (boletoVR <= 0 && boletoVT <= 0) {
  return [{ json: { _skip: 'sem boleto', boletoVR, boletoVT } }];
}

let boletoOrderId = '';
try {
  boletoOrderId = String($('HTTP Request6').first().json.allowanceOrderId || '');
} catch (e) {}

let drive;
try {
  drive = $('Emitir Pasta Drive').first().json;
} catch (e) {
  throw new Error('Pasta Drive não foi emitida antes da Solicitação de Pagamento.');
}

const documentosUrl = String(drive.documentosFolderUrl || '');
const documentosFolderId = String(drive.documentosFolderId || '');
const documentosFolderPath = String(drive.documentosFolderPath || '');

if (!documentosUrl) {
  throw new Error('documentosUrl vazio. A coluna DOCUMENTOS não será preenchida.');
}

const dt = new Date(dados.dataInicio + 'T00:00:00');
if (Number.isNaN(dt.getTime())) {
  throw new Error(`dataInicio inválida: ${dados.dataInicio}`);
}

const mes = dt.getMonth() + 1;

const monthGroups = {
  1: 'topics',
  2: 'group_mm07c71j',
  3: 'group_mm13efh7',
  4: 'group_mm204bv',
  5: 'group_mm31wvwc'
};

const groupId = monthGroups[mes] || 'group_mm31wvwc';

const mesLabels = [
  'JANEIRO',
  'FEVEREIRO',
  'MARÇO',
  'ABRIL',
  'MAIO',
  'JUNHO',
  'JULHO',
  'AGOSTO',
  'SETEMBRO',
  'OUTUBRO',
  'NOVEMBRO',
  'DEZEMBRO'
];

const competenciaLabel = mesLabels[mes - 1];

const tipoLabels = [];
if (boletoVR > 0) tipoLabels.push('CAJU');
if (boletoVT > 0) tipoLabels.push('CAJU VT');

const contratoMap = {
  SEMSA: 'SEMSA',
  DETRAN: 'DETRAN',
  'TRE PB': 'TRE PB',
  CETAM: 'CETAM',
  'SEDUC SEDE': 'SEDUC SEDE',
  'SEDUC ESCOLA': 'SEDUC ESCOLA',
  'SEDUC INTERIOR': 'SEDUC INTERIOR',
  ADMINISTRATIVO: 'ADMINISTRATIVO - CONTATO'
};

const contratoLabel = contratoMap[dados.contrato] || dados.contrato;

const hoje = new Date();
const dataHoje = hoje.toISOString().slice(0, 10);

const descricao = [
  `Intermitente: ${dados.nomeEmpregado}`,
  `Chapa: ${dados.chapaRM}`,
  `Periodo: ${dados.dataInicio} a ${dados.dataFim}`,
  `Boleto VR: R$ ${boletoVR.toFixed(2)}`,
  `Boleto VT: R$ ${boletoVT.toFixed(2)}`,
  `Pasta Drive: ${documentosFolderPath}`
].join(' | ');

const itemName = `INTERMITENTE - ${dados.nomeEmpregado}`;

const columnValues = {
  dropdown_mkwhxxs2: { labels: tipoLabels },
  dropdown_mkretdvv: { labels: [contratoLabel] },
  color_mkref5wt: { label: 'INTERMITENTE' },
  date_mkrer5tv: { date: dataHoje },
  status: { label: 'NÃO INICIADO' },
  color_mks0yady: { label: competenciaLabel },
  long_text_mkre1qa0: { text: descricao },
  numeric_mkrek29b: String(boletoVR),
  numeric_mkwhk2xr: String(boletoVT),
  text_mkrenhm: boletoOrderId,
  text_mkwhg4dn: boletoOrderId,
  text_mm1zyhcw: boletoOrderId,
  link_mkref9et: {
    url: documentosUrl,
    text: 'Pasta Drive'
  }
};

const columnValuesJson = JSON.stringify(columnValues);
const columnValuesEscaped = JSON.stringify(columnValuesJson);

const query = `mutation {
  create_item(
    board_id: ${BOARD_SOLICITACAO},
    group_id: ${JSON.stringify(groupId)},
    item_name: ${JSON.stringify(itemName)},
    column_values: ${columnValuesEscaped},
    create_labels_if_missing: true
  ) {
    id
  }
}`;

return [{
  json: {
    query,
    _debug: {
      boletoVR,
      boletoVT,
      boletoOrderId,
      documentosUrl,
      documentosFolderId,
      documentosFolderPath,
      contratoLabel,
      groupId
    }
  }
}];

// NÓ 24 — SOMENTE CRÉDITOS (rastreio, após subworkflow) — via AIONS /enviar-rm
const dados = $('Code in JavaScript8').first().json;
const hoje = new Date();
const anoComp = hoje.getFullYear();
const mesComp = hoje.getMonth() + 1;
const chapa = dados.chapaRM;
const nome = dados.nomeEmpregado;
const formatarValor = v => Number(v).toFixed(2).replace('.', ',');

function montarDadosXml(codBeneficio, vlrTotal, tpBen) {
  const valorRM = formatarValor(vlrTotal);
  const xml = `<PRJ3230976>
              <ZMDHSTBENFUNC>
                <ID>-1</ID>
                <CODCOLIGADA>3</CODCOLIGADA>
                <ANOCOMP>${anoComp}</ANOCOMP>
                <MESCOMP>${mesComp}</MESCOMP>
                <ANOREF>${anoComp}</ANOREF>
                <MESREF>${mesComp}</MESREF>
                <CHAPA>${chapa}</CHAPA>
                <NOME>${nome}</NOME>
                <CODBENEFICIO>${codBeneficio}</CODBENEFICIO>
                <VLRTOTAL>${valorRM}</VLRTOTAL>
                <TPBEN>${tpBen}</TPBEN>
                <CATFUN>1</CATFUN>
              </ZMDHSTBENFUNC>
            </PRJ3230976>`;
  return `<![CDATA[${xml}]]>`;
}

const registros = [];
if (dados.creditoVR > 0) registros.push({ tipo: 'CREDITO_VR', dadosXml: montarDadosXml(1, dados.creditoVR, 0), valor: dados.creditoVR });
if (dados.creditoVT > 0) registros.push({ tipo: 'CREDITO_VT', dadosXml: montarDadosXml(2, dados.creditoVT, 0), valor: dados.creditoVT });

return registros.map(r => ({ json: r }));

// Pega dados do Code 8 (Separar Crédito/Boleto), que espalha
// `...consolidado` e tem dataInicio/chapaRM/secaoRM/contrato/valorFinalVR/VT.
// Se preferir, pode usar `Code in JavaScript7` (Consolidar) — ambos têm os campos.
const dados = $('Code in JavaScript8').first().json;

if (!dados || !dados.dataInicio) {
  throw new Error('Sem dados upstream. Verificar Code in JavaScript8 e conexões.');
}

const eventos = [];
if ((dados.valorFinalVR || 0) > 0) eventos.push("100");
if ((dados.valorFinalVT || 0) > 0) eventos.push("110");

const dt = new Date(dados.dataInicio + "T00:00:00");
if (Number.isNaN(dt.getTime())) {
  throw new Error(`dataInicio invalida: ${dados.dataInicio}`);
}

return [{
  json: {
    tipo: "Diario",
    coligada: 3,
    anoComp: dt.getFullYear(),
    mesComp: dt.getMonth() + 1,
    contrato: dados.contrato,
    codSecao: dados.secaoRM,
    chapas: [String(dados.chapaRM).padStart(6, '0')],
    eventos
  }
}];

// ============================================================
// NÓ 2 — Extrair e Tratar Dados do Webhook
// ============================================================
// Entrada: payload bruto do webhook do Monday.com
// Saída: objeto limpo com todos os dados necessários para o fluxo
// ============================================================

const event = $input.first().json.body.event;
const cols = event.columnValues;

// --- Extração dos campos ---
// dropdown_mktadatt pode ter 2 entradas: [0]=titular substituído, [1]=intermitente.
// Pegamos o ÚLTIMO (intermitente é adicionado depois). Funciona mesmo com 1 só.
const chosen = cols.dropdown_mktadatt?.chosenValues || [];
if (chosen.length === 0) {
  throw new Error('dropdown_mktadatt sem chosenValues — coluna vazia.');
}
const nomeEmpregado = chosen[chosen.length - 1].name.trim();

const dataInicio = cols.date_mktayxhb.date;       // "2026-03-16"
const dataFim = cols.date_mktasnwq.date;           // "2026-03-20"
const optanteVtRaw = (cols.optante___vt?.label?.text || "NÃO").toUpperCase().trim();
const optanteVT = optanteVtRaw === "SIM" || optanteVtRaw === "SIM*";
const vtSoVolta = optanteVtRaw === "SIM*";
const trabalhaSabado = (cols.color_mktaavmp?.label?.text || "NÃO").toUpperCase() === "SIM";
const interior = (cols.color__1?.label?.text || "NÃO").toUpperCase() === "SIM";
const contratoOrgao = (cols.color_mktcnxwn?.label?.text || "").toUpperCase().trim();

// IDs do Monday para atualizações futuras
const boardId = event.boardId;
const itemId = event.pulseId;

// --- Tratamento do nome para o LIKE no RM ---
// AIONS API recebe o nome com % para o LIKE, ex: %JAMILE JORGINA DOS SANTOS%
const nomeLike = `%${nomeEmpregado}%`;

return [{
  json: {
    // Dados do empregado
    nomeEmpregado,
    nomeLike,

    // Configurações de benefício
    optanteVT,
    trabalhaSabado,
    interior,
    vtSoVolta,
    contratoOrgao,

    // Período
    dataInicio,
    dataFim,

    // IDs Monday (para atualizações futuras)
    boardId,
    itemId
  }
}];

// NÓ 23a — SOMENTE BOLETOS (vai antes do subworkflow) — via AIONS /enviar-rm
const dados = $('Code in JavaScript8').first().json;
const hoje = new Date();
const anoComp = hoje.getFullYear();
const mesComp = hoje.getMonth() + 1;
const chapa = dados.chapaRM;
const nome = dados.nomeEmpregado;
const formatarValor = v => Number(v).toFixed(2).replace('.', ',');

function montarDadosXml(codBeneficio, vlrTotal, tpBen) {
  const valorRM = formatarValor(vlrTotal);
  const xml = `<PRJ3230976>
              <ZMDHSTBENFUNC>
                <ID>-1</ID>
                <CODCOLIGADA>3</CODCOLIGADA>
                <ANOCOMP>${anoComp}</ANOCOMP>
                <MESCOMP>${mesComp}</MESCOMP>
                <ANOREF>${anoComp}</ANOREF>
                <MESREF>${mesComp}</MESREF>
                <CHAPA>${chapa}</CHAPA>
                <NOME>${nome}</NOME>
                <CODBENEFICIO>${codBeneficio}</CODBENEFICIO>
                <VLRTOTAL>${valorRM}</VLRTOTAL>
                <TPBEN>${tpBen}</TPBEN>
                <CATFUN>1</CATFUN>
              </ZMDHSTBENFUNC>
            </PRJ3230976>`;
  return `<![CDATA[${xml}]]>`;
}

const registros = [];
if (dados.boletoVR > 0) registros.push({ tipo: 'BOLETO_VR', dadosXml: montarDadosXml(1, dados.boletoVR, 0), valor: dados.boletoVR });
if (dados.boletoVT > 0) registros.push({ tipo: 'BOLETO_VT', dadosXml: montarDadosXml(2, dados.boletoVT, 0), valor: dados.boletoVT });

return registros.map(r => ({ json: r }));

// ============================================================
// NÓ 17 — Calcular Separação Crédito vs Boleto
// 2 dias VR + 2 dias VT → Crédito Caju
// Restante → Boleto PIX (e gera financeiro RM)
// ============================================================

