    funcao: dadosRM.funcaoRM,
    regraAplicada,
    vrDia,
    vtDia
  }
}];

// ============================================================
// NÓ 3 — Calcular Dias Úteis (VR e VT com regras distintas)
// ============================================================
// Entrada: dados tratados do Nó 2
// Saída: mesmos dados + diasVR e diasVT calculados
// ============================================================
// Regra:
//   - diasVR = dias úteis seg-sex (sábado NUNCA conta para VR)
//   - diasVT = dias úteis seg-sex, MAS se trabalhaSabado = true,
//     sábados no período também contam para VT
//   - Se optanteVT = false, diasVT = 0
//   - Domingos nunca contam
// ============================================================

const dados = $input.first().json;

const inicio = new Date(dados.dataInicio + "T00:00:00");
const fim = new Date(dados.dataFim + "T00:00:00");

let diasVR = 0;
let diasVT = 0;

// Percorre cada dia do período (inclusive início e fim)
const atual = new Date(inicio);
while (atual <= fim) {
  const diaSemana = atual.getDay(); // 0=Dom, 1=Seg, ..., 5=Sex, 6=Sáb

  if (diaSemana >= 1 && diaSemana <= 5) {
    // Seg a Sex: conta para VR e VT
    diasVR++;
    diasVT++;
  } else if (diaSemana === 6 && dados.trabalhaSabado) {
    // Sábado: conta APENAS para VT se trabalha sábado
    diasVT++;
  }
  // Domingo: não conta para nada

  atual.setDate(atual.getDate() + 1);
}

// Se não é optante de VT, zera os dias de VT
if (!dados.optanteVT) {
  diasVT = 0;
}

return [{
  json: {
    ...dados,
    diasVR,
    diasVT
  }
}];

