const raw = $json.body?.payload ?? $json.payload ?? '';
let payload;
try { payload = typeof raw === 'string' ? JSON.parse(raw) : raw; }
catch { return [{ json: { _statusCode: 400, _abort: true, erro: 'payload_invalido', mensagem: 'Campo payload deve ser JSON valido.' } }]; }

const docs = Array.isArray(payload?.documentos) ? payload.documentos : [];
if (docs.length === 0) return [{ json: { _statusCode: 400, _abort: true, erro: 'sem_documentos', mensagem: 'Nenhum documento enviado.' } }];

const binaries = $input.first().binary || {};
const binaryKeysRecebidas = Object.keys(binaries);
const out = [];
const erros = [];
function iso(v) { return /^\d{4}-\d{2}-\d{2}$/.test(String(v || '')); }
function normTipo(d) {
  const tipo = String(d.tipo_documento || d.tipoDocumento || '').toLowerCase();
  if (tipo === 'declaracao') return 'declaracao';
  if (tipo === 'atestado') return 'atestado';
  const label = String(d.tipo_documentacao_label || d.tipoDocumentacaoLabel || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase();
  return label.includes('DECLARACAO') ? 'declaracao' : 'atestado';
}
function modalidade(d) { return String(d.modalidade_contrato || d.modalidadeContrato || 'INTERMITENTE').toUpperCase(); }
function onlyDigits(v) { return String(v || '').replace(/\D+/g, ''); }
function pickBinary(id, index) {
  const candidates = [
    'doc_' + id,
    'atestado_' + id,
    'doc_' + index,
    'file_' + index,
    String(index)
  ];
  for (const key of candidates) {
    if (binaries[key]) return { key, file: binaries[key], candidates };
  }
  if (docs.length === 1 && binaryKeysRecebidas.length === 1) {
    const key = binaryKeysRecebidas[0];
    return { key, file: binaries[key], candidates };
  }
  return { key: null, file: null, candidates };
}

